import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { calendarEventUpdateSchema } from "@/lib/validations/calendar"
import { z } from "zod"

interface RouteContext {
  params: Promise<{ id: string }>
}

export async function GET(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const event = await db.calendarEvent.findUnique({
      where: { id }
    })

    if (!event) {
      return NextResponse.json({ error: "Event not found" }, { status: 404 })
    }

    return NextResponse.json(event)
  } catch (error) {
    console.error("[CALENDAR_EVENT_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function PATCH(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const body = await req.json()
    const parsed = calendarEventUpdateSchema.parse(body)

    const updateData: any = { ...parsed }
    if (parsed.startTime) updateData.startTime = new Date(parsed.startTime)
    if (parsed.endTime) updateData.endTime = new Date(parsed.endTime)

    // Ensure start time is before end time if both are updated or retrieved
    if (updateData.startTime || updateData.endTime) {
      const existing = await db.calendarEvent.findUnique({ where: { id } })
      if (!existing) {
        return NextResponse.json({ error: "Event not found" }, { status: 404 })
      }
      const start = updateData.startTime || new Date(existing.startTime)
      const end = updateData.endTime || new Date(existing.endTime)
      if (start >= end) {
        return NextResponse.json({ error: "Start time must be before end time" }, { status: 400 })
      }
    }

    const event = await db.calendarEvent.update({
      where: { id },
      data: updateData,
    })

    return NextResponse.json(event)
  } catch (error) {
    console.error("[CALENDAR_EVENT_PATCH]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function DELETE(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const event = await db.calendarEvent.findUnique({ where: { id } })

    if (!event) {
      return NextResponse.json({ error: "Event not found" }, { status: 404 })
    }

    await db.calendarEvent.delete({
      where: { id }
    })

    // Log activity
    await db.activityLog.create({
      data: {
        workspaceId: event.workspaceId,
        action: `Deleted calendar event "${event.title}"`,
        entityType: "EVENT",
        entityId: event.id,
      }
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error("[CALENDAR_EVENT_DELETE]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { calendarEventSchema } from "@/lib/validations/calendar"
import { z } from "zod"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const start = searchParams.get("start")
    const end = searchParams.get("end")
    const type = searchParams.get("type") || undefined

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const whereClause: any = {
      workspaceId,
    }

    if (type) {
      whereClause.type = type
    }

    // Date range filter
    if (start && end) {
      whereClause.startTime = {
        gte: new Date(start),
      }
      whereClause.endTime = {
        lte: new Date(end),
      }
    }

    const events = await db.calendarEvent.findMany({
      where: whereClause,
      orderBy: {
        startTime: "asc",
      }
    })

    return NextResponse.json(events)
  } catch (error) {
    console.error("[CALENDAR_EVENTS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function POST(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const body = await req.json()

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const parsed = calendarEventSchema.parse(body)

    // Ensure start time is before end time
    const start = new Date(parsed.startTime)
    const end = new Date(parsed.endTime)
    if (start >= end) {
      return NextResponse.json({ error: "Start time must be before end time" }, { status: 400 })
    }

    const event = await db.calendarEvent.create({
      data: {
        workspaceId,
        title: parsed.title,
        description: parsed.description,
        startTime: start,
        endTime: end,
        location: parsed.location,
        color: parsed.color,
        isAllDay: parsed.isAllDay,
        type: parsed.type,
      }
    })

    // Log activity
    await db.activityLog.create({
      data: {
        workspaceId,
        action: `Created calendar event "${event.title}"`,
        entityType: "EVENT",
        entityId: event.id,
      }
    })

    return NextResponse.json(event, { status: 201 })
  } catch (error) {
    console.error("[CALENDAR_EVENTS_POST]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const status = searchParams.get("status")
    const category = searchParams.get("category")
    const priority = searchParams.get("priority")
    const search = searchParams.get("search")

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const where: any = {
      workspaceId,
    }

    if (status && status !== "ALL") {
      where.status = status
    }
    if (category && category !== "ALL") {
      where.category = category
    }
    if (priority && priority !== "ALL") {
      where.priority = priority
    }
    if (search) {
      where.OR = [
        { title: { contains: search, mode: "insensitive" } },
        { description: { contains: search, mode: "insensitive" } },
      ]
    }

    const goals = await db.goal.findMany({
      where,
      include: {
        milestones: {
          orderBy: {
            position: "asc",
          },
        },
        project: {
          select: {
            id: true,
            name: true,
            color: true,
          },
        },
        task: {
          select: {
            id: true,
            title: true,
            status: true,
          },
        },
      },
      orderBy: {
        createdAt: "desc",
      },
    })

    return NextResponse.json(goals)
  } catch (error) {
    console.error("[GOALS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const {
      workspaceId,
      title,
      description,
      category,
      priority,
      targetDate,
      targetValue,
      currentValue,
      units,
      color,
      icon,
      tags,
      notes,
      projectId,
      taskId,
      milestones,
    } = body

    if (!workspaceId || !title) {
      return NextResponse.json({ error: "workspaceId and title are required" }, { status: 400 })
    }

    // Create the goal along with any milestones
    const goal = await db.goal.create({
      data: {
        workspaceId,
        title,
        description,
        category: category || "PERSONAL",
        priority: priority || "MEDIUM",
        targetDate: targetDate ? new Date(targetDate) : null,
        targetValue: targetValue !== undefined ? parseFloat(targetValue) : null,
        currentValue: currentValue !== undefined ? parseFloat(currentValue) : 0,
        units,
        color: color || "#3b82f6",
        icon: icon || "Target",
        tags,
        notes,
        projectId: projectId || null,
        taskId: taskId || null,
        status: "ACTIVE",
        progress: 0,
        milestones: milestones && milestones.length > 0 ? {
          create: milestones.map((m: { title: string; dueDate?: string }, index: number) => ({
            title: m.title,
            status: "TODO",
            isCompleted: false,
            position: index,
            dueDate: m.dueDate ? new Date(m.dueDate) : null,
          })),
        } : undefined,
      },
      include: {
        milestones: true,
      },
    })

    return NextResponse.json(goal)
  } catch (error) {
    console.error("[GOALS_POST]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id: habitId } = await params
    const body = await req.json()
    const { date, status, count, notes } = body

    if (!date) {
      return NextResponse.json({ error: "date is required" }, { status: 400 })
    }

    // Normalize date to YYYY-MM-DD 00:00:00 UTC
    const targetDate = new Date(date)
    targetDate.setUTCHours(0, 0, 0, 0)

    const habit = await db.habit.findUnique({
      where: { id: habitId },
    })

    if (!habit) {
      return NextResponse.json({ error: "Habit not found" }, { status: 404 })
    }

    // Toggle logic: if it already exists and status is COMPLETED, and we send status=COMPLETED, we delete it (untoggle)
    // Otherwise we create or update it.
    const existingHistory = await db.habitHistory.findUnique({
      where: {
        habitId_date: {
          habitId,
          date: targetDate,
        },
      },
    })

    if (existingHistory && status === "DELETE") {
      await db.habitHistory.delete({
        where: { id: existingHistory.id },
      })
    } else if (existingHistory) {
      await db.habitHistory.update({
        where: { id: existingHistory.id },
        data: {
          status: status || "COMPLETED",
          count: count !== undefined ? parseInt(count) : existingHistory.count,
          notes: notes !== undefined ? notes : existingHistory.notes,
        },
      })
    } else {
      await db.habitHistory.create({
        data: {
          habitId,
          date: targetDate,
          status: status || "COMPLETED",
          count: count !== undefined ? parseInt(count) : 1,
          notes,
        },
      })
    }

    // Fetch all history for this habit to recalculate streaks
    const allHistory = await db.habitHistory.findMany({
      where: {
        habitId,
        status: "COMPLETED",
      },
      orderBy: {
        date: "asc",
      },
    })

    // Calculate streaks
    const { currentStreak, longestStreak } = calculateStreaks(allHistory.map(h => h.date))

    // Update habit with new streaks
    const updatedHabit = await db.habit.update({
      where: { id: habitId },
      data: {
        currentStreak,
        longestStreak,
      },
      include: {
        history: {
          orderBy: {
            date: "desc",
          },
        },
      },
    })

    return NextResponse.json(updatedHabit)
  } catch (error) {
    console.error("[HABIT_HISTORY_POST]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

function calculateStreaks(dates: Date[]): { currentStreak: number; longestStreak: number } {
  if (dates.length === 0) {
    return { currentStreak: 0, longestStreak: 0 }
  }

  // Normalize dates to local YYYY-MM-DD strings for comparison
  const dateStrings = Array.from(
    new Set(
      dates.map(d => {
        const dateObj = new Date(d)
        return dateObj.toISOString().split("T")[0]
      })
    )
  ).sort()

  let longestStreak = 0
  let currentStreak = 0
  let tempStreak = 0

  // 1. Calculate longest streak
  for (let i = 0; i < dateStrings.length; i++) {
    if (i === 0) {
      tempStreak = 1
    } else {
      const prevDate = new Date(dateStrings[i - 1])
      const currDate = new Date(dateStrings[i])
      const diffTime = Math.abs(currDate.getTime() - prevDate.getTime())
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))

      if (diffDays === 1) {
        tempStreak++
      } else if (diffDays > 1) {
        longestStreak = Math.max(longestStreak, tempStreak)
        tempStreak = 1
      }
    }
  }
  longestStreak = Math.max(longestStreak, tempStreak)

  // 2. Calculate current streak
  // Get today's and yesterday's date strings in UTC/local
  const todayObj = new Date()
  const todayStr = todayObj.toISOString().split("T")[0]

  const yesterdayObj = new Date()
  yesterdayObj.setDate(yesterdayObj.getDate() - 1)
  const yesterdayStr = yesterdayObj.toISOString().split("T")[0]

  const hasCompletedToday = dateStrings.includes(todayStr)
  const hasCompletedYesterday = dateStrings.includes(yesterdayStr)

  if (!hasCompletedToday && !hasCompletedYesterday) {
    currentStreak = 0
  } else {
    // Start counting backwards from the most recent completed day (today or yesterday)
    let checkDate = hasCompletedToday ? todayObj : yesterdayObj
    let checkStr = checkDate.toISOString().split("T")[0]

    while (dateStrings.includes(checkStr)) {
      currentStreak++
      checkDate.setDate(checkDate.getDate() - 1)
      checkStr = checkDate.toISOString().split("T")[0]
    }
  }

  return { currentStreak, longestStreak }
}

