import { NextResponse } from "next/server"
import { db } from "@/lib/db"
import { logger } from "@/lib/logger"

export async function GET() {
  const startTime = Date.now()
  try {
    // 1. Verify database connectivity
    await db.$queryRaw`SELECT 1`

    // 2. Retrieve server metrics
    const memory = process.memoryUsage()
    const uptime = process.uptime()

    return NextResponse.json({
      status: "healthy",
      timestamp: new Date().toISOString(),
      latencyMs: Date.now() - startTime,
      uptime: `${Math.floor(uptime / 3600)}h ${Math.floor((uptime % 3600) / 60)}m ${Math.floor(uptime % 60)}s`,
      memory: {
        rss: `${Math.round(memory.rss / 1024 / 1024)}MB`,
        heapTotal: `${Math.round(memory.heapTotal / 1024 / 1024)}MB`,
        heapUsed: `${Math.round(memory.heapUsed / 1024 / 1024)}MB`,
        external: `${Math.round(memory.external / 1024 / 1024)}MB`,
      }
    })
  } catch (error: any) {
    logger.error("[HEALTH_CHECK_FAILED]", { error: error.message })
    return NextResponse.json({
      status: "unhealthy",
      timestamp: new Date().toISOString(),
      error: error.message
    }, { status: 503 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { logger } from "@/lib/logger"

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const { message, stack, componentStack } = body

    logger.error(`[CLIENT_CRASH] ${message}`, {
      stack,
      componentStack,
      userAgent: req.headers.get("user-agent"),
      ip: req.headers.get("x-forwarded-for") || "127.0.0.1"
    })

    return NextResponse.json({ success: true })
  } catch (error: any) {
    return NextResponse.json({ error: "Failed to log crash" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { z } from "zod"

const createNoteSchema = z.object({
  title: z.string().min(1, "Title is required").max(200).default("Untitled Note"),
  content: z.string().optional().nullable().default(""),
  folderId: z.string().optional().nullable(),
  isPinned: z.boolean().default(false),
  isFavorite: z.boolean().default(false),
  isArchived: z.boolean().default(false),
  isTrash: z.boolean().default(false),
})

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const folderId = searchParams.get("folderId")
    const isPinned = searchParams.get("isPinned") === "true" ? true : undefined
    const isFavorite = searchParams.get("isFavorite") === "true" ? true : undefined
    const isArchived = searchParams.get("isArchived") === "true"
    const isTrash = searchParams.get("isTrash") === "true"
    const search = searchParams.get("search") || ""

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const whereClause: any = {
      workspaceId,
      isArchived,
      isTrash,
    }

    if (folderId === "none") {
      whereClause.folderId = null
    } else if (folderId) {
      whereClause.folderId = folderId
    }

    if (isPinned) whereClause.isPinned = true
    if (isFavorite) whereClause.isFavorite = true

    if (search) {
      whereClause.OR = [
        { title: { contains: search, mode: "insensitive" } },
        { content: { contains: search, mode: "insensitive" } },
      ]
    }

    const notes = await db.note.findMany({
      where: whereClause,
      include: {
        folder: true,
      },
      orderBy: [
        { isPinned: "desc" },
        { updatedAt: "desc" },
      ]
    })

    return NextResponse.json(notes)
  } catch (error) {
    console.error("[NOTES_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

