import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const startDateParam = searchParams.get("startDate")
    const endDateParam = searchParams.get("endDate")
    const projectId = searchParams.get("projectId")

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    // Default to last 7 days if no dates provided
    const endDate = endDateParam ? new Date(endDateParam) : new Date()
    const startDate = startDateParam ? new Date(startDateParam) : new Date()
    if (!startDateParam) {
      startDate.setDate(endDate.getDate() - 7)
    }
    
    startDate.setHours(0, 0, 0, 0)
    endDate.setHours(23, 59, 59, 999)

    const dateDiffTime = Math.abs(endDate.getTime() - startDate.getTime())
    const dateDiffDays = Math.max(1, Math.ceil(dateDiffTime / (1000 * 60 * 60 * 24)))

    // --- 1. Fetch Time Entries ---
    const timeEntryWhere: any = {
      workspaceId,
      startTime: { gte: startDate, lte: endDate },
    }
    if (projectId) {
      timeEntryWhere.projectId = projectId
    }

    const timeEntries = await db.timeEntry.findMany({
      where: timeEntryWhere,
      orderBy: { startTime: "asc" },
      include: { task: true },
    })

    // --- 2. Fetch Tasks ---
    const taskWhere: any = {
      workspaceId,
    }
    if (projectId) {
      taskWhere.projectId = projectId
    }
    
    // Fetch tasks created or completed in the range
    const tasks = await db.task.findMany({
      where: {
        ...taskWhere,
        OR: [
          { createdAt: { gte: startDate, lte: endDate } },
          { completedAt: { gte: startDate, lte: endDate } },
        ],
      },
    })

    // --- 3. Fetch Habits & History ---
    const habits = await db.habit.findMany({
      where: {
        workspaceId,
        status: "ACTIVE",
      },
      include: {
        history: {
          where: {
            date: { gte: startDate, lte: endDate },
            status: "COMPLETED",
          },
        },
      },
    })

    // --- 4. Fetch Calendar Events (for planning score) ---
    const calendarEvents = await db.calendarEvent.findMany({
      where: {
        workspaceId,
        startTime: { gte: startDate, lte: endDate },
        type: "TIME_BLOCK",
      },
    })

    // ==========================================
    // METRICS CALCULATIONS
    // ==========================================

    // A. Time Metrics
    let totalSeconds = 0
    let productiveSeconds = 0
    let deepWorkSeconds = 0
    const projectTimeMap: Record<string, { name: string; seconds: number; color: string }> = {}
    const taskTimeMap: Record<string, { title: string; seconds: number }> = {}

    // Track hourly & daily distribution
    const hourlyDistribution = Array(24).fill(0)
    const dailyDistribution = Array(7).fill(0) // 0=Sun, 1=Mon...

    timeEntries.forEach((entry) => {
      const duration = entry.duration || 0
      totalSeconds += duration

      if (entry.isProductive) {
        productiveSeconds += duration
      }

      if (entry.type === "DEEP_WORK" || entry.type === "POMODORO") {
        deepWorkSeconds += duration
      }

      // Project allocation
      if (entry.projectId) {
        if (!projectTimeMap[entry.projectId]) {
          projectTimeMap[entry.projectId] = {
            name: entry.projectId, // fallback
            seconds: 0,
            color: "#3b82f6",
          }
        }
        projectTimeMap[entry.projectId].seconds += duration
      }

      // Task allocation
      if (entry.taskId && entry.task) {
        if (!taskTimeMap[entry.taskId]) {
          taskTimeMap[entry.taskId] = {
            title: entry.task.title,
            seconds: 0,
          }
        }
        taskTimeMap[entry.taskId].seconds += duration
      }

      // Hour of day (local)
      const startHour = new Date(entry.startTime).getHours()
      hourlyDistribution[startHour] += duration

      // Day of week (local)
      const startDay = new Date(entry.startTime).getDay()
      dailyDistribution[startDay] += duration
    })

    // B. Task Metrics
    const tasksCreated = tasks.filter(t => t.createdAt >= startDate && t.createdAt <= endDate).length
    const tasksCompleted = tasks.filter(t => t.completedAt && t.completedAt >= startDate && t.completedAt <= endDate).length

    // C. Habit Metrics
    let totalPossibleHabits = habits.length * dateDiffDays
    let actualHabitCompletions = habits.reduce((acc, h) => acc + h.history.length, 0)

    // D. Calendar Planning Metrics
    let timeBlockedSeconds = calendarEvents.reduce((acc, event) => {
      const diff = new Date(event.endTime).getTime() - new Date(event.startTime).getTime()
      return acc + Math.max(0, diff / 1000)
    }, 0)

    // ==========================================
    // PRODUCTIVITY SCORE ENGINE
    // ==========================================
    const focusScore = totalSeconds > 0 
      ? Math.round((productiveSeconds / totalSeconds) * 100) 
      : 0

    const consistencyScore = totalPossibleHabits > 0 
      ? Math.round((actualHabitCompletions / totalPossibleHabits) * 100) 
      : 0

    const completionScore = tasksCreated > 0 
      ? Math.round((tasksCompleted / tasksCreated) * 100) 
      : 0

    // Target: 2 hours of deep work per day
    const targetDeepWorkSeconds = dateDiffDays * 2 * 3600
    const deepWorkScore = targetDeepWorkSeconds > 0
      ? Math.min(100, Math.round((deepWorkSeconds / targetDeepWorkSeconds) * 100))
      : 0

    // Target: 50% of productive time is planned/blocked on calendar
    const planningScore = productiveSeconds > 0
      ? Math.min(100, Math.round((timeBlockedSeconds / productiveSeconds) * 100))
      : 0

    // Weighted Overall Productivity Index (OPI)
    const overallProductivityIndex = Math.round(
      0.3 * focusScore +
      0.2 * consistencyScore +
      0.2 * completionScore +
      0.15 * deepWorkScore +
      0.15 * planningScore
    )

    // ==========================================
    // TRENDS OVER TIME (Day-by-Day)
    // ==========================================
    const dayLabels: string[] = []
    const trendDataMap: Record<string, { date: string; productive: number; unproductive: number; tasks: number }> = {}

    for (let i = 0; i < dateDiffDays; i++) {
      const d = new Date(startDate)
      d.setDate(d.getDate() + i)
      const dateStr = d.toISOString().split("T")[0]
      dayLabels.push(dateStr)
      trendDataMap[dateStr] = {
        date: d.toLocaleDateString(undefined, { month: "short", day: "numeric" }),
        productive: 0,
        unproductive: 0,
        tasks: 0,
      }
    }

    // Populate trend time
    timeEntries.forEach((entry) => {
      const dateStr = new Date(entry.startTime).toISOString().split("T")[0]
      if (trendDataMap[dateStr]) {
        const hours = (entry.duration || 0) / 3600
        if (entry.isProductive) {
          trendDataMap[dateStr].productive += hours
        } else {
          trendDataMap[dateStr].unproductive += hours
        }
      }
    })

    // Populate trend tasks completed
    tasks.forEach((task) => {
      if (task.completedAt) {
        const dateStr = new Date(task.completedAt).toISOString().split("T")[0]
        if (trendDataMap[dateStr]) {
          trendDataMap[dateStr].tasks += 1
        }
      }
    })

    const trends = Object.values(trendDataMap)

    // ==========================================
    // PEAK HOURS & DAYS
    // ==========================================
    const peakHourValue = Math.max(...hourlyDistribution)
    const peakHour = hourlyDistribution.indexOf(peakHourValue)

    const daysOfWeek = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"]
    const peakDayValue = Math.max(...dailyDistribution)
    const peakDayIndex = dailyDistribution.indexOf(peakDayValue)
    const peakDay = daysOfWeek[peakDayIndex]

    // ==========================================
    // SMART INSIGHTS & RECOMMENDATIONS
    // ==========================================
    const insights: string[] = []
    
    if (focusScore < 70 && totalSeconds > 0) {
      insights.push(`Your focus score is ${focusScore}%. Try using the Pomodoro timer or blocking distracting sites to stay on task.`)
    }
    if (completionScore < 50 && tasksCreated > 5) {
      insights.push(`You completed only ${completionScore}% of new tasks. Consider breaking larger tasks into smaller milestones.`)
    }
    if (consistencyScore < 60 && habits.length > 0) {
      insights.push(`Habit consistency is at ${consistencyScore}%. Try setting reminders for your key habits earlier in the day.`)
    }
    if (deepWorkSeconds < targetDeepWorkSeconds * 0.5 && totalSeconds > 0) {
      insights.push(`Your deep work hours are below target. Try scheduling a dedicated 90-minute focus block in your calendar.`)
    }
    if (planningScore < 30 && productiveSeconds > 3600 * 5) {
      insights.push(`Only ${planningScore}% of your productive time was time-blocked. Try 'time blocking' your tasks to increase efficiency.`)
    }
    if (insights.length === 0) {
      insights.push("Excellent work! You are maintaining a highly balanced and productive routine across all metrics.")
    }

    return NextResponse.json({
      summary: {
        totalHours: Math.round((totalSeconds / 3600) * 10) / 10,
        productiveHours: Math.round((productiveSeconds / 3600) * 10) / 10,
        deepWorkHours: Math.round((deepWorkSeconds / 3600) * 10) / 10,
        tasksCompleted,
        tasksCreated,
        habitsCompleted: actualHabitCompletions,
        habitsTotal: habits.length,
      },
      scores: {
        focus: focusScore,
        consistency: consistencyScore,
        completion: completionScore,
        deepWork: deepWorkScore,
        planning: planningScore,
        overall: overallProductivityIndex,
      },
      allocation: {
        projects: Object.entries(projectTimeMap).map(([id, data]) => ({
          id,
          name: data.name,
          value: Math.round((data.seconds / 3600) * 10) / 10,
          color: data.color,
        })),
        tasks: Object.entries(taskTimeMap).map(([id, data]) => ({
          id,
          title: data.title,
          value: Math.round((data.seconds / 3600) * 10) / 10,
        })).sort((a, b) => b.value - a.value).slice(0, 5),
      },
      trends,
      peakTime: {
        bestHour: `${peakHour}:00`,
        bestDay: peakDay,
        hourly: hourlyDistribution.map((seconds, hour) => ({ hour: `${hour}:00`, hours: Math.round((seconds / 3600) * 10) / 10 })),
        daily: dailyDistribution.map((seconds, index) => ({ day: daysOfWeek[index].substring(0, 3), hours: Math.round((seconds / 3600) * 10) / 10 })),
      },
      insights,
    })
  } catch (error) {
    console.error("[REPORTS_ANALYTICS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

const WORKSPACE_ID = "cm0q9z8x0000008l4f1h7a3n2"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId") || WORKSPACE_ID

    // Fetch all workspace data in parallel
    const [
      projects,
      tasks,
      timeEntries,
      goals,
      habits,
      notes,
      calendarEvents,
    ] = await Promise.all([
      db.project.findMany({ where: { workspaceId } }),
      db.task.findMany({ where: { workspaceId } }),
      db.timeEntry.findMany({ where: { workspaceId } }),
      db.goal.findMany({ where: { workspaceId }, include: { milestones: true } }),
      db.habit.findMany({ where: { workspaceId }, include: { history: true } }),
      db.note.findMany({ where: { workspaceId } }),
      db.calendarEvent.findMany({ where: { workspaceId } }),
    ])

    const backup = {
      version: "1.0",
      exportedAt: new Date().toISOString(),
      workspaceId,
      data: {
        projects,
        tasks,
        timeEntries,
        goals,
        habits,
        notes,
        calendarEvents,
      },
    }

    return NextResponse.json(backup)
  } catch (error) {
    console.error("[BACKUP_EXPORT_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const { data, workspaceId = WORKSPACE_ID } = body

    if (!data) {
      return NextResponse.json({ error: "Invalid backup data" }, { status: 400 })
    }

    // Execute restore inside a transaction to prevent partial updates on failure
    await db.$transaction(async (tx) => {
      // 1. Clear existing workspace data
      await tx.timeEntry.deleteMany({ where: { workspaceId } })
      
      await tx.taskDependency.deleteMany({
        where: {
          OR: [
            { task: { workspaceId } },
            { dependsOnTask: { workspaceId } }
          ]
        },
      })
      
      await tx.checklistItem.deleteMany({
        where: {
          task: { workspaceId },
        },
      })
      
      // Nullify parentTaskIds to avoid self-referencing foreign key violations
      await tx.task.updateMany({
        where: { workspaceId },
        data: { parentTaskId: null }
      })
      
      await tx.task.deleteMany({ where: { workspaceId } })
      await tx.project.deleteMany({ where: { workspaceId } })
      
      await tx.goalMilestone.deleteMany({
        where: {
          goal: { workspaceId },
        },
      })
      
      await tx.goal.deleteMany({ where: { workspaceId } })
      
      await tx.habitHistory.deleteMany({
        where: {
          habit: { workspaceId },
        },
      })
      
      await tx.habit.deleteMany({ where: { workspaceId } })
      await tx.note.deleteMany({ where: { workspaceId } })
      
      // Nullify folder parentIds and delete folders
      await tx.folder.updateMany({
        where: { workspaceId },
        data: { parentId: null }
      })
      await tx.folder.deleteMany({ where: { workspaceId } })
      
      await tx.calendarEvent.deleteMany({ where: { workspaceId } })

      // 2. Restore Projects
      if (data.projects && data.projects.length > 0) {
        await tx.project.createMany({
          data: data.projects.map((p: any) => ({
            id: p.id,
            workspaceId,
            name: p.name,
            color: p.color,
            status: p.status,
            createdAt: new Date(p.createdAt),
            updatedAt: new Date(p.updatedAt),
            isArchived: p.isArchived,
            deletedAt: p.deletedAt ? new Date(p.deletedAt) : null,
          })),
        })
      }

      // 3. Restore Tasks
      if (data.tasks && data.tasks.length > 0) {
        await tx.task.createMany({
          data: data.tasks.map((t: any) => ({
            id: t.id,
            workspaceId,
            projectId: t.projectId,
            parentTaskId: t.parentTaskId,
            title: t.title,
            description: t.description,
            status: t.status,
            priority: t.priority,
            position: t.position,
            dueDate: t.dueDate ? new Date(t.dueDate) : null,
            completedAt: t.completedAt ? new Date(t.completedAt) : null,
            estimatedTime: t.estimatedTime,
            actualTime: t.actualTime,
            recurrenceRule: t.recurrenceRule,
            isFavorite: t.isFavorite,
            createdAt: new Date(t.createdAt),
            updatedAt: new Date(t.updatedAt),
            isArchived: t.isArchived,
            deletedAt: t.deletedAt ? new Date(t.deletedAt) : null,
          })),
        })
      }

      // 4. Restore Time Entries
      if (data.timeEntries && data.timeEntries.length > 0) {
        await tx.timeEntry.createMany({
          data: data.timeEntries.map((te: any) => ({
            id: te.id,
            workspaceId,
            projectId: te.projectId,
            taskId: te.taskId,
            description: te.description,
            startTime: new Date(te.startTime),
            endTime: te.endTime ? new Date(te.endTime) : null,
            duration: te.duration,
            isProductive: te.isProductive,
            type: te.type,
            mood: te.mood,
            energyLevel: te.energyLevel,
            productivityRating: te.productivityRating,
            notes: te.notes,
            tags: te.tags,
            createdAt: new Date(te.createdAt),
            updatedAt: new Date(te.updatedAt),
          })),
        })
      }

      // 5. Restore Goals & Milestones
      if (data.goals && data.goals.length > 0) {
        for (const g of data.goals) {
          await tx.goal.create({
            data: {
              id: g.id,
              workspaceId,
              title: g.title,
              description: g.description,
              category: g.category || "PERSONAL",
              priority: g.priority || "MEDIUM",
              status: g.status,
              targetDate: g.targetDate ? new Date(g.targetDate) : null,
              progress: g.progress,
              currentValue: g.currentValue || 0,
              targetValue: g.targetValue,
              units: g.units,
              color: g.color || "#3b82f6",
              icon: g.icon || "Target",
              tags: g.tags,
              notes: g.notes,
              projectId: g.projectId,
              taskId: g.taskId,
              createdAt: new Date(g.createdAt),
              updatedAt: new Date(g.updatedAt),
              milestones: g.milestones && g.milestones.length > 0 ? {
                create: g.milestones.map((m: any) => ({
                  id: m.id,
                  title: m.title,
                  status: m.status,
                  dueDate: m.dueDate ? new Date(m.dueDate) : null,
                  isCompleted: m.isCompleted,
                  position: m.position,
                  createdAt: new Date(m.createdAt),
                  updatedAt: new Date(m.updatedAt),
                })),
              } : undefined,
            },
          })
        }
      }

      // 6. Restore Habits & History
      if (data.habits && data.habits.length > 0) {
        for (const h of data.habits) {
          await tx.habit.create({
            data: {
              id: h.id,
              workspaceId,
              title: h.title,
              description: h.description,
              frequency: h.frequency,
              customDays: h.customDays,
              targetCount: h.targetCount,
              isNegative: h.isNegative,
              status: h.status,
              color: h.color,
              icon: h.icon,
              currentStreak: h.currentStreak,
              longestStreak: h.longestStreak,
              projectId: h.projectId,
              taskId: h.taskId,
              createdAt: new Date(h.createdAt),
              updatedAt: new Date(h.updatedAt),
              history: h.history && h.history.length > 0 ? {
                create: h.history.map((hist: any) => ({
                  id: hist.id,
                  status: hist.status,
                  count: hist.count,
                  date: new Date(hist.date),
                  notes: hist.notes,
                  createdAt: new Date(hist.createdAt),
                })),
              } : undefined,
            },
          })
        }
      }

      // 7. Restore Notes
      if (data.notes && data.notes.length > 0) {
        await tx.note.createMany({
          data: data.notes.map((n: any) => ({
            id: n.id,
            workspaceId,
            folderId: n.folderId,
            title: n.title,
            content: n.content,
            isPinned: n.isPinned,
            isFavorite: n.isFavorite,
            isArchived: n.isArchived,
            isTrash: n.isTrash,
            createdAt: new Date(n.createdAt),
            updatedAt: new Date(n.updatedAt),
          })),
        })
      }

      // 8. Restore Calendar Events
      if (data.calendarEvents && data.calendarEvents.length > 0) {
        await tx.calendarEvent.createMany({
          data: data.calendarEvents.map((ce: any) => ({
            id: ce.id,
            workspaceId,
            title: ce.title,
            description: ce.description,
            startTime: new Date(ce.startTime),
            endTime: new Date(ce.endTime),
            location: ce.location,
            color: ce.color,
            isAllDay: ce.isAllDay,
            type: ce.type,
            createdAt: new Date(ce.createdAt),
            updatedAt: new Date(ce.updatedAt),
          })),
        })
      }
    }, {
      timeout: 20000 // 20 seconds
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error("[BACKUP_RESTORE_POST]", error)
    return NextResponse.json({ error: "Failed to restore backup" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

const DEFAULT_PREFERENCES = {
  theme: "system",
  accentColor: "#3b82f6",
  fontSize: "base",
  uiDensity: "default",
  borderRadius: "xl",
  pomodoroWorkDuration: 25 * 60,
  pomodoroShortBreakDuration: 5 * 60,
  pomodoroLongBreakDuration: 15 * 60,
  defaultCalendarView: "week",
  defaultTaskPriority: "MEDIUM",
  notificationsEnabled: true,
  notificationSound: true,
  reducedMotion: false,
  highContrast: false,
}

async function getOrCreateUser() {
  let user = await db.user.findFirst()
  if (!user) {
    user = await db.user.create({
      data: {
        email: "alex@example.com",
        name: "Alex Developer",
      },
    })
  }
  return user
}

export async function GET(req: NextRequest) {
  try {
    const user = await getOrCreateUser()

    let preference = await db.userPreference.findUnique({
      where: { userId: user.id },
    })

    if (!preference) {
      preference = await db.userPreference.create({
        data: {
          userId: user.id,
          preferences: DEFAULT_PREFERENCES,
        },
      })
    }

    return NextResponse.json(preference.preferences)
  } catch (error) {
    console.error("[SETTINGS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function PATCH(req: NextRequest) {
  try {
    const user = await getOrCreateUser()
    const body = await req.json()

    let preference = await db.userPreference.findUnique({
      where: { userId: user.id },
    })

    const currentPrefs = preference ? (preference.preferences as any) : DEFAULT_PREFERENCES
    const newPrefs = { ...currentPrefs, ...body }

    if (preference) {
      preference = await db.userPreference.update({
        where: { userId: user.id },
        data: { preferences: newPrefs },
      })
    } else {
      preference = await db.userPreference.create({
        data: {
          userId: user.id,
          preferences: newPrefs,
        },
      })
    }

    return NextResponse.json(preference.preferences)
  } catch (error) {
    console.error("[SETTINGS_PATCH]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { IntegrationService } from "@/lib/integration-service"
import { taskUpdateSchema } from "@/lib/validations/task"
import { z } from "zod"

interface RouteContext {
  params: Promise<{ id: string }>
}

export async function GET(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const task = await db.task.findUnique({
      where: { id },
      include: {
        project: true,
        checklists: {
          orderBy: { position: "asc" }
        },
        subtasks: {
          where: { isArchived: false },
          include: {
            checklists: true,
            _count: { select: { subtasks: true, checklists: true } }
          },
          orderBy: { position: "asc" }
        },
        dependencies: {
          include: {
            dependsOnTask: true
          }
        },
        dependents: {
          include: {
            task: true
          }
        }
      }
    })

    if (!task) {
      return NextResponse.json({ error: "Task not found" }, { status: 404 })
    }

    return NextResponse.json(task)
  } catch (error) {
    console.error("[TASK_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function PATCH(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const body = await req.json()
    const parsed = taskUpdateSchema.parse(body)

    const updateData: any = { ...parsed }
    if (parsed.dueDate) {
      updateData.dueDate = new Date(parsed.dueDate)
    }
    if (parsed.status === "DONE" && !updateData.completedAt) {
      updateData.completedAt = new Date()
    } else if (parsed.status && parsed.status !== "DONE") {
      updateData.completedAt = null
    }

    let task;
    if (parsed.status) {
      // Use IntegrationService to handle status update + side-effects
      task = await IntegrationService.handleTaskCompletion(id, parsed.status)

      // Update any other remaining fields
      const remainingUpdates = { ...updateData }
      delete remainingUpdates.status
      delete remainingUpdates.completedAt

      if (Object.keys(remainingUpdates).length > 0) {
        task = await db.task.update({
          where: { id },
          data: remainingUpdates,
          include: {
            project: true,
            checklists: true,
          }
        })
      } else {
        // Refetch with includes to match return signature
        task = await db.task.findUnique({
          where: { id },
          include: {
            project: true,
            checklists: true,
          }
        })
      }
    } else {
      task = await db.task.update({
        where: { id },
        data: updateData,
        include: {
          project: true,
          checklists: true,
        }
      })
    }

    await db.activityLog.create({
      data: {
        workspaceId: task!.workspaceId,
        action: `Updated task "${task!.title}"`,
        entityType: "TASK",
        entityId: task!.id,
      }
    })

    return NextResponse.json(task)
  } catch (error) {
    console.error("[TASK_PATCH]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function DELETE(req: NextRequest, { params }: RouteContext) {
  try {
    const { id } = await params
    const task = await db.task.findUnique({ where: { id } })

    if (!task) {
      return NextResponse.json({ error: "Task not found" }, { status: 404 })
    }

    await db.task.delete({
      where: { id }
    })

    await db.activityLog.create({
      data: {
        workspaceId: task.workspaceId,
        action: `Permanently deleted task "${task.title}"`,
        entityType: "TASK",
        entityId: task.id,
      }
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error("[TASK_DELETE]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { taskReorderSchema } from "@/lib/validations/task"
import { z } from "zod"

export async function PATCH(req: NextRequest) {
  try {
    const body = await req.json()
    const parsed = taskReorderSchema.parse(body)

    // Execute in a transaction to update positions of multiple tasks
    const updates = parsed.taskIds.map((id, index) => {
      const data: any = {
        position: (index + 1) * 1000,
      }
      if (parsed.status) {
        data.status = parsed.status
        if (parsed.status === "DONE") {
          data.completedAt = new Date()
        } else {
          data.completedAt = null
        }
      }
      return db.task.update({
        where: { id },
        data,
      })
    })

    await db.$transaction(updates)

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error("[TASKS_REORDER_PATCH]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { taskSchema } from "@/lib/validations/task"
import { z } from "zod"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const projectId = searchParams.get("projectId") || undefined
    const status = searchParams.get("status") || undefined
    const priority = searchParams.get("priority") || undefined
    const parentTaskId = searchParams.get("parentTaskId")
    const showArchived = searchParams.get("showArchived") === "true"

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    // Build filter query
    const whereClause: any = {
      workspaceId,
      isArchived: showArchived,
    }

    if (projectId) whereClause.projectId = projectId
    if (status) whereClause.status = status
    if (priority) whereClause.priority = priority

    // By default, if parentTaskId is not specified, we only fetch top-level tasks to prevent massive nested trees in a single list
    if (parentTaskId === "null") {
      whereClause.parentTaskId = null
    } else if (parentTaskId) {
      whereClause.parentTaskId = parentTaskId
    }

    const tasks = await db.task.findMany({
      where: whereClause,
      include: {
        project: true,
        checklists: {
          orderBy: { position: "asc" }
        },
        _count: {
          select: { subtasks: true, checklists: true }
        }
      },
      orderBy: [
        { position: "asc" },
        { createdAt: "desc" }
      ]
    })

    return NextResponse.json(tasks)
  } catch (error) {
    console.error("[TASKS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const parsed = taskSchema.parse(body)

    // Find the max position to place it at the end
    const lastTask = await db.task.findFirst({
      where: {
        workspaceId,
        status: parsed.status,
        parentTaskId: null
      },
      orderBy: { position: "desc" },
      select: { position: true }
    })

    const newPosition = lastTask ? lastTask.position + 1000 : 1000

    const task = await db.task.create({
      data: {
        workspaceId,
        title: parsed.title,
        description: parsed.description,
        status: parsed.status,
        priority: parsed.priority,
        dueDate: parsed.dueDate ? new Date(parsed.dueDate) : null,
        projectId: parsed.projectId,
        estimatedTime: parsed.estimatedTime,
        actualTime: parsed.actualTime,
        position: newPosition,
      },
      include: {
        project: true,
        checklists: true,
      }
    })

    // Log activity
    await db.activityLog.create({
      data: {
        workspaceId,
        action: `Created task "${task.title}"`,
        entityType: "TASK",
        entityId: task.id,
      }
    })

    return NextResponse.json(task, { status: 201 })
  } catch (error) {
    console.error("[TASKS_POST]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"
import { z } from "zod"

const manualEntrySchema = z.object({
  projectId: z.string().optional().nullable(),
  taskId: z.string().optional().nullable(),
  description: z.string().optional().nullable(),
  startTime: z.string().datetime(),
  endTime: z.string().datetime(),
  isProductive: z.boolean().default(true),
  type: z.enum(["NORMAL", "POMODORO", "STOPWATCH", "COUNTDOWN", "DEEP_WORK"]).default("NORMAL"),
  mood: z.number().int().min(1).max(5).optional().nullable(),
  energyLevel: z.number().int().min(1).max(5).optional().nullable(),
  productivityRating: z.number().int().min(1).max(5).optional().nullable(),
  notes: z.string().optional().nullable(),
  tags: z.string().optional().nullable(),
})

const updateEntrySchema = manualEntrySchema.partial()

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const projectId = searchParams.get("projectId") || undefined
    const taskId = searchParams.get("taskId") || undefined
    const limit = searchParams.get("limit") ? parseInt(searchParams.get("limit")!, 10) : 50

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const whereClause: any = {
      workspaceId,
      endTime: { not: null }, // Only fetch completed sessions
    }

    if (projectId) whereClause.projectId = projectId
    if (taskId) whereClause.taskId = taskId

    const entries = await db.timeEntry.findMany({
      where: whereClause,
      include: {
        project: true,
        task: true,
      },
      orderBy: {
        startTime: "desc",
      },
      take: limit,
    })

    return NextResponse.json(entries)
  } catch (error) {
    console.error("[TIME_ENTRIES_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function POST(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")
    const body = await req.json()

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const parsed = manualEntrySchema.parse(body)
    const start = new Date(parsed.startTime)
    const end = new Date(parsed.endTime)
    const duration = Math.round((end.getTime() - start.getTime()) / 1000)

    if (duration < 0) {
      return NextResponse.json({ error: "End time must be after start time" }, { status: 400 })
    }

    const entry = await db.timeEntry.create({
      data: {
        workspaceId,
        projectId: parsed.projectId,
        taskId: parsed.taskId,
        description: parsed.description,
        startTime: start,
        endTime: end,
        duration,
        isProductive: parsed.isProductive,
        type: parsed.type,
        mood: parsed.mood,
        energyLevel: parsed.energyLevel,
        productivityRating: parsed.productivityRating,
        notes: parsed.notes,
        tags: parsed.tags,
      },
      include: {
        project: true,
        task: true,
      }
    })

    return NextResponse.json(entry, { status: 201 })
  } catch (error) {
    console.error("[TIME_ENTRIES_POST]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function PATCH(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const id = searchParams.get("id")
    const body = await req.json()

    if (!id) {
      return NextResponse.json({ error: "id is required" }, { status: 400 })
    }

    const parsed = updateEntrySchema.parse(body)
    const updateData: any = { ...parsed }

    if (parsed.startTime) updateData.startTime = new Date(parsed.startTime)
    if (parsed.endTime) updateData.endTime = new Date(parsed.endTime)

    // Recalculate duration if times changed
    if (updateData.startTime || updateData.endTime) {
      const existing = await db.timeEntry.findUnique({ where: { id } })
      if (!existing) {
        return NextResponse.json({ error: "Entry not found" }, { status: 404 })
      }
      const start = updateData.startTime || new Date(existing.startTime)
      const end = updateData.endTime || (existing.endTime ? new Date(existing.endTime) : new Date())
      const duration = Math.round((end.getTime() - start.getTime()) / 1000)
      if (duration < 0) {
        return NextResponse.json({ error: "End time must be after start time" }, { status: 400 })
      }
      updateData.duration = duration
    }

    const entry = await db.timeEntry.update({
      where: { id },
      data: updateData,
      include: {
        project: true,
        task: true,
      }
    })

    return NextResponse.json(entry)
  } catch (error) {
    console.error("[TIME_ENTRIES_PATCH]", error)
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.issues }, { status: 422 })
    }
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function DELETE(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const id = searchParams.get("id")

    if (!id) {
      return NextResponse.json({ error: "id is required" }, { status: 400 })
    }

    await db.timeEntry.delete({ where: { id } })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error("[TIME_ENTRIES_DELETE]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url)
    const workspaceId = searchParams.get("workspaceId")

    if (!workspaceId) {
      return NextResponse.json({ error: "workspaceId is required" }, { status: 400 })
    }

    const now = new Date()
    const startOfWeek = new Date(now)
    startOfWeek.setDate(now.getDate() - now.getDay())
    startOfWeek.setHours(0, 0, 0, 0)

    // Fetch all completed time entries for the current week
    const weeklyEntries = await db.timeEntry.findMany({
      where: {
        workspaceId,
        endTime: { not: null },
        startTime: { gte: startOfWeek },
      },
      select: {
        duration: true,
        startTime: true,
        isProductive: true,
        type: true,
        projectId: true,
        project: {
          select: { name: true, color: true }
        }
      }
    })

    // Compute stats
    let totalDuration = 0
    let productiveDuration = 0
    let deepWorkDuration = 0
    let pomodoroCount = 0

    const projectDistributionMap = new Map<string, { name: string; color: string; duration: number }>()
    const dailyActivityMap = new Map<number, number>() // day of week -> duration in seconds

    // Initialize daily activity map for 7 days
    for (let i = 0; i < 7; i++) {
      dailyActivityMap.set(i, 0)
    }

    weeklyEntries.forEach(entry => {
      const duration = entry.duration || 0
      totalDuration += duration
      if (entry.isProductive) productiveDuration += duration
      if (entry.type === "DEEP_WORK") deepWorkDuration += duration
      if (entry.type === "POMODORO") pomodoroCount += 1

      // Group by project
      if (entry.projectId && entry.project) {
        const existing = projectDistributionMap.get(entry.projectId)
        if (existing) {
          existing.duration += duration
        } else {
          projectDistributionMap.set(entry.projectId, {
            name: entry.project.name,
            color: entry.project.color || "hsl(var(--primary))",
            duration,
          })
        }
      } else {
        const existing = projectDistributionMap.get("no-project")
        if (existing) {
          existing.duration += duration
        } else {
          projectDistributionMap.set("no-project", {
            name: "No Project",
            color: "#64748b", // slate-500
            duration,
          })
        }
      }

      // Group by day of week
      const day = new Date(entry.startTime).getDay()
      const currentDayDuration = dailyActivityMap.get(day) || 0
      dailyActivityMap.set(day, currentDayDuration + duration)
    })

    const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"]
    const dailyActivity = Array.from(dailyActivityMap.entries()).map(([dayIdx, duration]) => ({
      name: days[dayIdx],
      hours: Math.round((duration / 3600) * 10) / 10,
    }))

    const projectDistribution = Array.from(projectDistributionMap.entries()).map(([_, data]) => ({
      name: data.name,
      value: Math.round((data.duration / 3600) * 10) / 10,
      color: data.color,
    }))

    const stats = {
      totalHours: Math.round((totalDuration / 3600) * 10) / 10,
      productivityScore: totalDuration > 0 ? Math.round((productiveDuration / totalDuration) * 100) : 0,
      deepWorkHours: Math.round((deepWorkDuration / 3600) * 10) / 10,
      pomodorosCompleted: pomodoroCount,
      dailyActivity,
      projectDistribution,
    }

    return NextResponse.json(stats)
  } catch (error) {
    console.error("[TIME_STATS_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/lib/db"

async function getOrCreateUser() {
  let user = await db.user.findFirst()
  if (!user) {
    user = await db.user.create({
      data: {
        email: "jane@example.com",
        name: "Jane Doe",
      },
    })
  }
  return user
}

export async function GET(req: NextRequest) {
  try {
    const user = await getOrCreateUser()
    return NextResponse.json(user)
  } catch (error) {
    console.error("[USER_GET]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

export async function PATCH(req: NextRequest) {
  try {
    const user = await getOrCreateUser()
    const body = await req.json()
    const { name, email } = body

    const updatedUser = await db.user.update({
      where: { id: user.id },
      data: {
        name: name !== undefined ? name : undefined,
        email: email !== undefined ? email : undefined,
      },
    })

    return NextResponse.json(updatedUser)
  } catch (error) {
    console.error("[USER_PATCH]", error)
    return NextResponse.json({ error: "Internal server error" }, { status: 500 })
  }
}

"use client"

import { useState, use } from "react"
import { useProject, useArchiveProject } from "@/hooks/use-projects-queries"
import { ProjectHeader } from "@/features/projects/components/project-header"
import { ProjectOverview } from "@/features/projects/components/project-overview"
import dynamic from "next/dynamic"

const ProjectDashboard = dynamic(
  () => import("@/features/projects/components/project-dashboard").then((mod) => mod.ProjectDashboard),
  {
    ssr: false,
    loading: () => <Skeleton className="h-[400px] w-full rounded-xl mt-8" />
  }
)
import { EditProjectModal } from "@/features/projects/components/edit-project-modal"
import { DeleteProjectModal } from "@/features/projects/components/delete-project-modal"
import { Skeleton } from "@/components/ui/skeleton"
import { toast } from "sonner"
import { useRouter } from "next/navigation"

export default function ProjectDetailsPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter()
  const resolvedParams = use(params)
  const { data: project, isLoading, isError } = useProject(resolvedParams.id)
  const archiveProject = useArchiveProject()

  const [isEditOpen, setIsEditOpen] = useState(false)
  const [isDeleteOpen, setIsDeleteOpen] = useState(false)

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background p-6 max-w-[1600px] mx-auto w-full space-y-8">
        <Skeleton className="h-24 w-full rounded-xl" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {[...Array(4)].map((_, i) => (
            <Skeleton key={i} className="h-32 rounded-xl" />
          ))}
        </div>
      </div>
    )
  }

  if (isError || !project) {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center text-destructive">
        <h2>Project not found</h2>
        <p className="text-muted-foreground mt-2">The project may have been deleted or you don't have access.</p>
      </div>
    )
  }

  const handleArchive = () => {
    archiveProject.mutate({ id: project.id, isArchived: !project.isArchived }, {
      onSuccess: () => {
        toast.success(`Project ${project.isArchived ? 'restored' : 'archived'} successfully`)
      }
    })
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <main className="flex-1 px-6 max-w-[1600px] w-full mx-auto">
        <ProjectHeader 
          project={project} 
          onEdit={() => setIsEditOpen(true)}
          onDelete={() => setIsDeleteOpen(true)}
          onArchive={handleArchive}
        />

        <ProjectOverview project={project} />

        <ProjectDashboard projectId={project.id} />
      </main>

      <EditProjectModal project={project} open={isEditOpen} onOpenChange={setIsEditOpen} />
      <DeleteProjectModal 
        project={project} 
        open={isDeleteOpen} 
        onOpenChange={(open) => {
          setIsDeleteOpen(open)
          // If the modal was closed and the project is deleted, the query will fail and show "not found", but we should redirect.
          if (!open && !project) {
            router.push("/projects")
          }
        }} 
      />
    </div>
  )
}

"use client"

import { useState } from "react"
import { useProjectsStore } from "@/stores/projects-store"
import { ProjectsToolbar } from "@/features/projects/components/projects-toolbar"
import { ProjectsGrid } from "@/features/projects/components/projects-grid"
import { ProjectsList } from "@/features/projects/components/projects-list"
