import {
  CommandDialog,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandSeparator,
} from "@/components/ui/command"
import { Button } from "@/components/ui/button"
import {
  Clock,
  CheckSquare,
  Folder,
  LayoutDashboard,
  Target,
  Activity,
  FileText,
  Calendar,
  Settings,
  Sun,
  Moon,
