"use client"

import * as React from "react"
import { useOrganization } from "@/hooks/use-organization"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"

export function QuickAddModal() {
  const [open, setOpen] = React.useState(false)
  const [taskName, setTaskName] = React.useState("")
  const addTask = useOrganization((state) => state.addTask)

  React.useEffect(() => {
    const down = (e: KeyboardEvent) => {
      // Cmd+Shift+A (Note: shiftKey makes e.key uppercase 'A')
      if ((e.key === "A" || e.key === "a") && (e.metaKey || e.ctrlKey) && e.shiftKey) {
        e.preventDefault()
        setOpen((open) => !open)
      }
    }
    document.addEventListener("keydown", down)
    return () => document.removeEventListener("keydown", down)
  }, [])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!taskName.trim()) return

    // Natural Language Parsing simulation
    let projectId = null
    let titleStr = taskName.trim()

    // Smart Parsing
    const lower = titleStr.toLowerCase()
    if (lower.includes("tomorrow")) {
      titleStr = titleStr.replace(/tomorrow/i, "").trim()
      // In a real app, set dueDate to tomorrow here
    } else if (lower.includes("today")) {
      titleStr = titleStr.replace(/today/i, "").trim()
      // In a real app, set dueDate to today here
    }

    addTask(titleStr, projectId)
    setTaskName("")
    setOpen(false)
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogContent className="sm:max-w-[600px] p-0 overflow-hidden border border-border/50 shadow-2xl bg-card/95 backdrop-blur-xl">
        <form onSubmit={handleSubmit} className="flex flex-col">
          <div className="px-5 py-3 border-b border-border/50 bg-muted/20 flex items-center justify-between">
            <DialogTitle className="text-xs font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
              Quick Add
            </DialogTitle>
            <div className="flex gap-1">
              <kbd className="pointer-events-none inline-flex h-5 items-center gap-1 rounded border bg-muted px-1.5 font-mono text-[10px] font-medium text-muted-foreground opacity-100">
                <span className="text-xs">Γîÿ</span>
              </kbd>
              <kbd className="pointer-events-none inline-flex h-5 items-center gap-1 rounded border bg-muted px-1.5 font-mono text-[10px] font-medium text-muted-foreground opacity-100">
                Γçº
              </kbd>
              <kbd className="pointer-events-none inline-flex h-5 items-center gap-1 rounded border bg-muted px-1.5 font-mono text-[10px] font-medium text-muted-foreground opacity-100">
                A
              </kbd>
            </div>
          </div>
          <Input 
            autoFocus
            value={taskName}
            onChange={(e) => setTaskName(e.target.value)}
            placeholder="e.g., Update brand guidelines #Acme @Tomorrow" 
            className="border-0 h-16 rounded-none focus-visible:ring-0 text-lg px-5 placeholder:text-muted-foreground/40 bg-transparent"
          />
          {/* Smart Parse Preview */}
          {(taskName.toLowerCase().includes('tomorrow') || taskName.toLowerCase().includes('today')) && (
            <div className="px-5 py-3 border-t border-border/50 bg-primary/5 flex items-center gap-2 text-xs font-medium text-primary">
              Γ£¿ Smart Parse: Due Date will be set to {taskName.toLowerCase().includes('tomorrow') ? 'Tomorrow' : 'Today'}
            </div>
          )}
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import { calendarEventSchema, CalendarEventInput } from "@/lib/validations/calendar"
import { useCreateCalendarEvent } from "@/hooks/use-calendar-queries"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Loader2 } from "lucide-react"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Checkbox } from "@/components/ui/checkbox"

interface CreateEventModalProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  initialDate?: Date
}

const PRESET_COLORS = [
  "hsl(var(--primary))",
  "#ef4444", // red
  "#f97316", // orange
  "#f59e0b", // amber
  "#10b981", // emerald
  "#06b6d4", // cyan
  "#3b82f6", // blue
  "#8b5cf6", // violet
  "#d946ef", // fuchsia
]

export function CreateEventModal({ open, onOpenChange, initialDate }: CreateEventModalProps) {
  const createEvent = useCreateCalendarEvent()

  const getInitialDateTimeString = (date?: Date, hourOffset = 0) => {
    const d = date ? new Date(date) : new Date()
    if (!date) {
      d.setMinutes(0, 0, 0)
      d.setHours(d.getHours() + hourOffset)
    } else {
      d.setHours(9 + hourOffset, 0, 0)
    }
    // Format to yyyy-MM-ddThh:mm matching input datetime-local
    const tzOffset = d.getTimezoneOffset() * 60000
    const localISOTime = new Date(d.getTime() - tzOffset).toISOString().slice(0, 16)
    return localISOTime
  }

  const form = useForm<CalendarEventInput>({
    resolver: zodResolver(calendarEventSchema) as any,
    defaultValues: {
      title: "",
      description: "",
      startTime: getInitialDateTimeString(initialDate, 1),
      endTime: getInitialDateTimeString(initialDate, 2),
      location: "",
      color: PRESET_COLORS[0],
      isAllDay: false,
      type: "EVENT"
    }
  })

  const onSubmit = (data: CalendarEventInput) => {
    // Convert local datetime-local strings to ISO string for API
    const formattedData = {
      ...data,
      startTime: new Date(data.startTime).toISOString(),
      endTime: new Date(data.endTime).toISOString(),
    }

    createEvent.mutate(formattedData, {
      onSuccess: () => {
        form.reset()
        onOpenChange(false)
      }
    })
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[480px]">
        <DialogHeader>
          <DialogTitle>Create Event</DialogTitle>
          <DialogDescription>
            Schedule a new event or time block in your calendar.
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={form.handleSubmit(onSubmit as any)} className="space-y-4 pt-2">
          <div className="space-y-1">
            <Label htmlFor="event-title">Title</Label>
            <Input
              id="event-title"
              placeholder="e.g. Design Sync"
              {...form.register("title")}
              disabled={createEvent.isPending}
            />
            {form.formState.errors.title && (
              <p className="text-xs text-destructive">{form.formState.errors.title.message}</p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <Label htmlFor="start-time">Start Time</Label>
              <Input
                id="start-time"
                type="datetime-local"
                {...form.register("startTime")}
                disabled={createEvent.isPending}
              />
              {form.formState.errors.startTime && (
                <p className="text-xs text-destructive">{form.formState.errors.startTime.message}</p>
              )}
            </div>

            <div className="space-y-1">
              <Label htmlFor="end-time">End Time</Label>
              <Input
                id="end-time"
                type="datetime-local"
                {...form.register("endTime")}
                disabled={createEvent.isPending}
              />
              {form.formState.errors.endTime && (
                <p className="text-xs text-destructive">{form.formState.errors.endTime.message}</p>
              )}
            </div>
          </div>

          <div className="flex items-center gap-2 py-1">
            <Checkbox
              id="is-all-day"
              checked={form.watch("isAllDay")}
              onCheckedChange={(checked) => form.setValue("isAllDay", !!checked)}
              disabled={createEvent.isPending}
            />
            <Label htmlFor="is-all-day" className="text-xs cursor-pointer select-none">All-day Event</Label>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <Label>Type</Label>
              <Select
                disabled={createEvent.isPending}
                value={form.watch("type")}
                onValueChange={(val: any) => form.setValue("type", val)}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="EVENT">Calendar Event</SelectItem>
                  <SelectItem value="TIME_BLOCK">Deep Work Block</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-1">
              <Label htmlFor="event-loc">Location</Label>
              <Input
                id="event-loc"
                placeholder="e.g. Zoom, Meeting Room 1"
                {...form.register("location")}
                disabled={createEvent.isPending}
              />
            </div>
          </div>

          <div className="space-y-1">
            <Label htmlFor="event-desc">Description</Label>
            <Textarea
              id="event-desc"
              placeholder="Add notes or agenda..."
              rows={3}
              {...form.register("description")}
              disabled={createEvent.isPending}
            />
          </div>

          <div className="space-y-1">
            <Label>Color Code</Label>
            <div className="flex flex-wrap gap-2">
              {PRESET_COLORS.map((color) => (
                <button
                  key={color}
                  type="button"
                  className={`w-7 h-7 rounded-full border-2 transition-all ${
                    form.watch("color") === color 
                      ? "border-primary scale-110 shadow-sm" 
                      : "border-transparent hover:scale-105"
                  }`}
                  style={{ backgroundColor: color }}
                  onClick={() => form.setValue("color", color)}
                  disabled={createEvent.isPending}
                />
              ))}
            </div>
          </div>

          <DialogFooter className="pt-2">
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={createEvent.isPending}>
              Cancel
            </Button>
            <Button type="submit" disabled={createEvent.isPending}>
              {createEvent.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Create Event
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

