"use client"

import { useState, useEffect } from "react"
import { useTasks, useUpdateTask } from "@/hooks/use-tasks-queries"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Checkbox } from "@/components/ui/checkbox"
import { Plus, GripVertical, Calendar, Sparkles, Trash2 } from "lucide-react"
import { cn } from "@/lib/utils"

export function DailyPlanner() {
  const { data: tasks, isLoading } = useTasks()
  const updateTask = useUpdateTask()

  const [newPriorityTitle, setNewPriorityTitle] = useState("")
  const [priorities, setPriorities] = useState<{ id: string; title: string; completed: boolean }[]>([])

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem("chronos-daily-focus")
    if (saved) {
      try {
        setPriorities(JSON.parse(saved))
      } catch (e) {
        console.error("Failed to load daily focus from localStorage:", e)
      }
    }
  }, [])

  // Save to localStorage whenever priorities change
  const savePriorities = (updated: typeof priorities) => {
    setPriorities(updated)
    localStorage.setItem("chronos-daily-focus", JSON.stringify(updated))
  }

  const handleAddPriority = (e: React.FormEvent) => {
    e.preventDefault()
    if (!newPriorityTitle.trim()) return
    const updated = [
      ...priorities,
      { id: Date.now().toString(), title: newPriorityTitle.trim(), completed: false }
    ]
    savePriorities(updated)
    setNewPriorityTitle("")
  }

  const togglePriority = (id: string) => {
    const updated = priorities.map(p => p.id === id ? { ...p, completed: !p.completed } : p)
    savePriorities(updated)
  }

  const handleDeletePriority = (id: string) => {
    const updated = priorities.filter(p => p.id !== id)
    savePriorities(updated)
  }

  const handleDragStart = (e: React.DragEvent, task: any) => {
    // Pack task details into drag transfer
    e.dataTransfer.setData("application/json", JSON.stringify({
      title: task.title,
      description: task.description,
      taskId: task.id,
      projectId: task.projectId,
    }))
  }

  const unscheduledTasks = (tasks || []).filter((task: any) => !task.dueDate && task.status !== "DONE")

  return (
    <div className="space-y-6">
      {/* Daily Priorities */}
      <Card className="border-border/60 bg-card/60 backdrop-blur-sm">
        <CardHeader className="pb-3">
          <CardTitle className="text-sm font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5">
            <Sparkles className="w-4 h-4 text-amber-500" />
            Daily Focus Priorities
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="space-y-2">
            {priorities.length === 0 ? (
              <p className="text-xs text-muted-foreground text-center py-4">
                No focus priorities set for today. Add one below!
              </p>
            ) : (
              priorities.map((priority) => (
                <div key={priority.id} className="flex items-center justify-between p-1.5 hover:bg-accent/20 rounded-lg group">
                  <div className="flex items-center gap-3">
                    <Checkbox
                      checked={priority.completed}
                      onCheckedChange={() => togglePriority(priority.id)}
                    />
                    <span className={cn("text-xs font-medium", priority.completed && "line-through text-muted-foreground")}>
                      {priority.title}
                    </span>
                  </div>
                  <button
                    onClick={() => handleDeletePriority(priority.id)}
                    className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive transition-opacity cursor-pointer p-0.5"
                    aria-label="Delete focus priority"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddPriority} className="flex gap-2">
            <Input
              placeholder="Add daily focus..."
              value={newPriorityTitle}
              onChange={(e) => setNewPriorityTitle(e.target.value)}
              className="h-8 text-xs bg-background/20"
            />
            <Button type="submit" size="sm" className="h-8 px-2.5 shrink-0">
              <Plus className="w-3.5 h-3.5" />
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Unscheduled Tasks for Drag & Drop Time Blocking */}
      <Card className="border-border/60 bg-card/60 backdrop-blur-sm">
        <CardHeader className="pb-3">
          <CardTitle className="text-sm font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5">
            <Calendar className="w-4 h-4 text-primary" />
            Unscheduled Tasks
          </CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-2 animate-pulse">
              <div className="h-8 bg-muted rounded" />
              <div className="h-8 bg-muted rounded" />
            </div>
          ) : unscheduledTasks.length === 0 ? (
            <div className="py-8 text-center text-xs text-muted-foreground">
              All tasks are scheduled!
            </div>
          ) : (
            <div className="space-y-2 max-h-[300px] overflow-y-auto pr-1">
              {unscheduledTasks.map((task: any) => (
                <div
                  key={task.id}
                  draggable
                  onDragStart={(e) => handleDragStart(e, task)}
                  className="flex items-center gap-3 p-2 bg-background/30 hover:bg-background/70 border rounded-lg cursor-grab active:cursor-grabbing group transition-all"
                >
                  <GripVertical className="w-3.5 h-3.5 text-muted-foreground shrink-0" />
                  <span className="text-xs font-semibold truncate text-foreground group-hover:text-primary transition-colors">
                    {task.title}
                  </span>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { useEffect } from "react"
import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import { calendarEventSchema, CalendarEventInput } from "@/lib/validations/calendar"
import { useCalendarEvent, useUpdateCalendarEvent, useDeleteCalendarEvent } from "@/hooks/use-calendar-queries"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Loader2, Trash2 } from "lucide-react"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Checkbox } from "@/components/ui/checkbox"

interface EditEventModalProps {
  eventId: string | null
  open: boolean
  onOpenChange: (open: boolean) => void
}

const PRESET_COLORS = [
  "hsl(var(--primary))",
  "#ef4444", "#f97316", "#f59e0b", "#10b981", 
  "#06b6d4", "#3b82f6", "#8b5cf6", "#d946ef"
]

export function EditEventModal({ eventId, open, onOpenChange }: EditEventModalProps) {
  const { data: event, isLoading } = useCalendarEvent(eventId)
  const updateEvent = useUpdateCalendarEvent()
  const deleteEvent = useDeleteCalendarEvent()

  const getFormattedDateTimeString = (dateString?: string) => {
    if (!dateString) return ""
    const d = new Date(dateString)
    const tzOffset = d.getTimezoneOffset() * 60000
    return new Date(d.getTime() - tzOffset).toISOString().slice(0, 16)
  }

  const form = useForm<CalendarEventInput>({
    resolver: zodResolver(calendarEventSchema) as any,
    defaultValues: {
      title: "",
      description: "",
      startTime: "",
      endTime: "",
      location: "",
      color: PRESET_COLORS[0],
      isAllDay: false,
      type: "EVENT"
    }
  })

  useEffect(() => {
    if (event) {
      form.reset({
        title: event.title,
        description: event.description || "",
        startTime: getFormattedDateTimeString(event.startTime),
        endTime: getFormattedDateTimeString(event.endTime),
        location: event.location || "",
        color: event.color || PRESET_COLORS[0],
        isAllDay: event.isAllDay,
        type: event.type as any,
      })
    }
  }, [event, form])

  const onSubmit = (data: CalendarEventInput) => {
    if (!eventId) return
    const formattedData = {
      ...data,
      startTime: new Date(data.startTime).toISOString(),
      endTime: new Date(data.endTime).toISOString(),
    }

    updateEvent.mutate({ id: eventId, data: formattedData }, {
      onSuccess: () => {
        onOpenChange(false)
      }
    })
  }

  const handleDelete = () => {
    if (!eventId) return
    deleteEvent.mutate(eventId, {
      onSuccess: () => {
        onOpenChange(false)
      }
    })
  }

  if (!event) return null

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[480px]">
        <DialogHeader>
          <DialogTitle>Edit Event</DialogTitle>
          <DialogDescription>
            Update or delete your calendar item.
          </DialogDescription>
        </DialogHeader>
        {isLoading ? (
          <div className="py-20 flex items-center justify-center">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : (
          <form onSubmit={form.handleSubmit(onSubmit as any)} className="space-y-4 pt-2">
            <div className="space-y-1">
              <Label htmlFor="edit-event-title">Title</Label>
              <Input
                id="edit-event-title"
                placeholder="e.g. Design Sync"
                {...form.register("title")}
                disabled={updateEvent.isPending}
              />
              {form.formState.errors.title && (
                <p className="text-xs text-destructive">{form.formState.errors.title.message}</p>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label htmlFor="edit-start-time">Start Time</Label>
                <Input
                  id="edit-start-time"
                  type="datetime-local"
                  {...form.register("startTime")}
                  disabled={updateEvent.isPending}
                />
              </div>

              <div className="space-y-1">
                <Label htmlFor="edit-end-time">End Time</Label>
                <Input
                  id="edit-end-time"
                  type="datetime-local"
                  {...form.register("endTime")}
                  disabled={updateEvent.isPending}
                />
              </div>
            </div>

            <div className="flex items-center gap-2 py-1">
              <Checkbox
                id="edit-is-all-day"
                checked={form.watch("isAllDay")}
                onCheckedChange={(checked) => form.setValue("isAllDay", !!checked, { shouldDirty: true })}
                disabled={updateEvent.isPending}
              />
              <Label htmlFor="edit-is-all-day" className="text-xs cursor-pointer select-none">All-day Event</Label>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>Type</Label>
                <Select
                  disabled={updateEvent.isPending}
                  value={form.watch("type")}
                  onValueChange={(val: any) => form.setValue("type", val, { shouldDirty: true })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="EVENT">Calendar Event</SelectItem>
                    <SelectItem value="TIME_BLOCK">Deep Work Block</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-1">
                <Label htmlFor="edit-event-loc">Location</Label>
                <Input
                  id="edit-event-loc"
                  placeholder="e.g. Zoom, Meeting Room 1"
                  {...form.register("location")}
                  disabled={updateEvent.isPending}
                />
              </div>
            </div>

            <div className="space-y-1">
              <Label htmlFor="edit-event-desc">Description</Label>
              <Textarea
                id="edit-event-desc"
                placeholder="Add notes or agenda..."
                rows={3}
                {...form.register("description")}
                disabled={updateEvent.isPending}
              />
            </div>

            <div className="space-y-1">
              <Label>Color Code</Label>
              <div className="flex flex-wrap gap-2">
                {PRESET_COLORS.map((color) => (
                  <button
                    key={color}
                    type="button"
                    className={`w-7 h-7 rounded-full border-2 transition-all ${
                      form.watch("color") === color 
                        ? "border-primary scale-110 shadow-sm" 
                        : "border-transparent hover:scale-105"
                    }`}
                    style={{ backgroundColor: color }}
                    onClick={() => form.setValue("color", color, { shouldDirty: true })}
                    disabled={updateEvent.isPending}
                  />
                ))}
              </div>
            </div>

            <DialogFooter className="pt-2 flex justify-between sm:justify-between">
              <Button 
                type="button" 
                variant="destructive" 
                size="icon" 
                onClick={handleDelete}
                disabled={deleteEvent.isPending}
              >
                <Trash2 className="h-4 w-4" />
              </Button>
              <div className="flex gap-2">
                <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={updateEvent.isPending}>
                  Cancel
                </Button>
                <Button type="submit" disabled={updateEvent.isPending || !form.formState.isDirty}>
                  {updateEvent.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Save Changes
                </Button>
              </div>
            </DialogFooter>
          </form>
        )}
      </DialogContent>
    </Dialog>
  )
}

