"use client"

import { useCalendarStore } from "@/stores/calendar-store"
import { useCalendarEvents } from "@/hooks/use-calendar-queries"
import { cn } from "@/lib/utils"
import { isSameDay, format } from "date-fns"

const HOURS = Array.from({ length: 24 }, (_, i) => i)
const HOUR_HEIGHT = 70 // slightly taller for single day view

export function CalendarDayView() {
  const { selectedDate, setSelectedEventId } = useCalendarStore()
  const day = new Date(selectedDate)

  // Query events for the selected day range
  const startOfDay = new Date(day)
  startOfDay.setHours(0, 0, 0, 0)
  const endOfDay = new Date(day)
  endOfDay.setHours(23, 59, 59, 999)

  const { data: events } = useCalendarEvents({
    start: startOfDay.toISOString(),
    end: endOfDay.toISOString(),
  })

  const dayEvents = (events || []).filter((event: any) => !event.isAllDay)

  const getEventPosition = (event: any) => {
    const start = new Date(event.startTime)
    const end = new Date(event.endTime)

    const startHours = start.getHours() + start.getMinutes() / 60
    const endHours = end.getHours() + end.getMinutes() / 60
    const duration = endHours - startHours

    return {
      top: `${startHours * HOUR_HEIGHT}px`,
      height: `${Math.max(0.5, duration) * HOUR_HEIGHT}px`,
    }
  }

  return (
    <div className="flex flex-col h-[600px] border rounded-xl bg-card overflow-hidden">
      {/* Day header */}
      <div className="border-b bg-muted/30 p-4 text-center">
        <h2 className="text-lg font-bold text-foreground">
          {format(day, "EEEE, MMMM d, yyyy")}
        </h2>
      </div>

      {/* Grid container */}
      <div className="flex-1 overflow-y-auto relative flex">
        {/* Hour labels column */}
        <div className="w-[70px] border-r shrink-0 select-none bg-muted/5">
          {HOURS.map((hour) => (
            <div 
              key={hour} 
              className="text-[11px] text-muted-foreground/80 font-semibold text-right pr-3.5 relative"
              style={{ height: `${HOUR_HEIGHT}px`, top: "-6px" }}
            >
              {hour === 0 ? "12 AM" : hour === 12 ? "12 PM" : hour > 12 ? `${hour - 12} PM` : `${hour} AM`}
            </div>
          ))}
        </div>

        {/* Single day hourly column */}
        <div className="flex-1 relative h-[1680px]">
          {/* Horizontal hour helper lines */}
          {HOURS.map((hour) => (
            <div 
              key={hour} 
              className="border-b border-border/40 w-full" 
              style={{ height: `${HOUR_HEIGHT}px` }} 
            />
          ))}

          {/* Absolute positioned events */}
          {dayEvents.map((event: any) => {
            const pos = getEventPosition(event)
            return (
              <div
                key={event.id}
                onClick={() => setSelectedEventId(event.id)}
                className="absolute left-4 right-4 rounded-xl px-4 py-3 text-xs font-bold text-white border transition-all hover:scale-[1.005] hover:shadow-lg z-10 cursor-pointer shadow-md flex flex-col justify-between"
                style={{
                  ...pos,
                  backgroundColor: event.color || "var(--primary)",
                  borderColor: event.color || "var(--primary)",
                }}
              >
                <div className="space-y-1">
                  <div className="font-bold text-sm truncate">{event.title}</div>
                  {event.description && (
                    <div className="text-[10px] opacity-90 font-normal line-clamp-2">{event.description}</div>
                  )}
                </div>
                <div className="text-[10px] opacity-90 font-semibold flex justify-between items-center mt-2">
                  <span>{format(new Date(event.startTime), "h:mm a")} - {format(new Date(event.endTime), "h:mm a")}</span>
                  {event.location && <span className="opacity-75">{event.location}</span>}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

"use client"

import { useCalendarStore } from "@/stores/calendar-store"
import { useCalendarEvents } from "@/hooks/use-calendar-queries"
import { cn } from "@/lib/utils"
import { startOfMonth, endOfMonth, startOfWeek, endOfWeek, eachDayOfInterval, isSameMonth, isSameDay, format } from "date-fns"

interface CalendarMonthViewProps {
  onDayClick: (date: Date) => void
}

export function CalendarMonthView({ onDayClick }: CalendarMonthViewProps) {
  const { selectedDate, setSelectedEventId } = useCalendarStore()
  const currentMonthDate = new Date(selectedDate)

  const monthStart = startOfMonth(currentMonthDate)
  const monthEnd = endOfMonth(monthStart)
  const startDate = startOfWeek(monthStart)
  const endDate = endOfWeek(monthEnd)

  const days = eachDayOfInterval({ start: startDate, end: endDate })

  // Query events for the visible month range
  const { data: events } = useCalendarEvents({
    start: startDate.toISOString(),
    end: endDate.toISOString(),
  })

  const getEventsForDay = (day: Date) => {
    return (events || []).filter((event: any) => isSameDay(new Date(event.startTime), day))
  }

  return (
    <div className="flex flex-col h-full min-h-[600px] border rounded-xl overflow-hidden bg-card">
      {/* Weekday headers */}
      <div className="grid grid-cols-7 border-b bg-muted/30 text-center py-2.5 text-xs font-semibold text-muted-foreground">
        <div>Sun</div>
        <div>Mon</div>
        <div>Tue</div>
        <div>Wed</div>
        <div>Thu</div>
        <div>Fri</div>
        <div>Sat</div>
      </div>

      {/* Days grid */}
      <div className="grid grid-cols-7 flex-1">
        {days.map((day, idx) => {
          const dayEvents = getEventsForDay(day)
          const isCurrentMonth = isSameMonth(day, currentMonthDate)
          const isToday = isSameDay(day, new Date())

          return (
            <div
              key={idx}
              onClick={() => onDayClick(day)}
              className={cn(
                "border-r border-b last:border-r-0 p-1.5 flex flex-col min-h-[100px] transition-colors duration-150 cursor-pointer hover:bg-accent/20",
                !isCurrentMonth && "bg-muted/10 text-muted-foreground/60"
              )}
            >
              <div className="flex justify-between items-center mb-1">
                <span
                  className={cn(
                    "text-xs font-semibold w-6 h-6 rounded-full flex items-center justify-center",
                    isToday && "bg-primary text-primary-foreground shadow-sm",
                    !isToday && isCurrentMonth && "text-foreground",
                    !isToday && !isCurrentMonth && "text-muted-foreground"
                  )}
                >
                  {format(day, "d")}
                </span>
              </div>

              <div className="flex-1 space-y-1 overflow-y-auto max-h-[80px]">
                {dayEvents.slice(0, 3).map((event: any) => (
                  <div
                    key={event.id}
                    onClick={(e) => {
                      e.stopPropagation()
                      setSelectedEventId(event.id)
                    }}
                    className="text-[10px] font-semibold px-2 py-0.5 rounded truncate text-white border transition-all hover:brightness-95 hover:scale-[1.02]"
                    style={{ 
                      backgroundColor: event.color || "var(--primary)",
                      borderColor: event.color || "var(--primary)" 
                    }}
                  >
                    {event.title}
                  </div>
                ))}
                {dayEvents.length > 3 && (
                  <div className="text-[9px] text-muted-foreground font-semibold px-1">
                    + {dayEvents.length - 3} more
                  </div>
                )}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

"use client"

import { useCalendarStore } from "@/stores/calendar-store"
import { useCalendarEvents } from "@/hooks/use-calendar-queries"
import { cn } from "@/lib/utils"
import { startOfWeek, endOfWeek, eachDayOfInterval, isSameDay, format } from "date-fns"

const HOURS = Array.from({ length: 24 }, (_, i) => i)
const HOUR_HEIGHT = 60 // pixels per hour

export function CalendarWeekView() {
  const { selectedDate, setSelectedEventId } = useCalendarStore()
  const currentWeekDate = new Date(selectedDate)

  const startDate = startOfWeek(currentWeekDate)
  const endDate = endOfWeek(currentWeekDate)
  const days = eachDayOfInterval({ start: startDate, end: endDate })

  // Query events for the visible week range
  const { data: events } = useCalendarEvents({
    start: startDate.toISOString(),
    end: endDate.toISOString(),
  })

  const getEventsForDay = (day: Date) => {
    return (events || []).filter((event: any) => isSameDay(new Date(event.startTime), day) && !event.isAllDay)
  }

  const getEventPosition = (event: any) => {
    const start = new Date(event.startTime)
    const end = new Date(event.endTime)

    const startHours = start.getHours() + start.getMinutes() / 60
    const endHours = end.getHours() + end.getMinutes() / 60
    const duration = endHours - startHours

    return {
      top: `${startHours * HOUR_HEIGHT}px`,
      height: `${Math.max(0.5, duration) * HOUR_HEIGHT}px`,
    }
  }

  return (
    <div className="flex flex-col h-[600px] border rounded-xl bg-card overflow-hidden">
      {/* Week headers */}
      <div className="grid grid-cols-[60px_1fr] border-b bg-muted/30">
        <div className="border-r py-3"></div>
        <div className="grid grid-cols-7 text-center py-2 text-xs font-semibold">
          {days.map((day, idx) => {
            const isToday = isSameDay(day, new Date())
            return (
              <div key={idx} className="flex flex-col items-center gap-0.5">
                <span className="text-muted-foreground">{format(day, "eee")}</span>
                <span className={cn(
                  "w-6 h-6 rounded-full flex items-center justify-center font-bold",
                  isToday ? "bg-primary text-primary-foreground shadow-sm" : "text-foreground"
                )}>
                  {format(day, "d")}
                </span>
              </div>
            )
          })}
        </div>
      </div>

      {/* Grid container */}
      <div className="flex-1 overflow-y-auto relative flex">
        {/* Hour labels column */}
        <div className="w-[60px] border-r shrink-0 select-none bg-muted/5">
          {HOURS.map((hour) => (
            <div 
              key={hour} 
              className="text-[10px] text-muted-foreground/80 font-medium text-right pr-2.5 relative"
              style={{ height: `${HOUR_HEIGHT}px`, top: "-6px" }}
            >
              {hour === 0 ? "12 AM" : hour === 12 ? "12 PM" : hour > 12 ? `${hour - 12} PM` : `${hour} AM`}
            </div>
          ))}
        </div>

        {/* Days hourly columns */}
        <div className="flex-1 grid grid-cols-7 relative h-[1440px]">
          {/* Vertical grid lines */}
          {days.map((day, dayIdx) => {
            const dayEvents = getEventsForDay(day)

            return (
              <div key={dayIdx} className="border-r last:border-r-0 relative h-full">
                {/* Horizontal hour helper lines */}
                {HOURS.map((hour) => (
                  <div 
                    key={hour} 
                    className="border-b border-border/40 w-full" 
                    style={{ height: `${HOUR_HEIGHT}px` }} 
                  />
                ))}

                {/* Absolute positioned events */}
                {dayEvents.map((event: any) => {
                  const pos = getEventPosition(event)
                  return (
                    <div
                      key={event.id}
                      onClick={() => setSelectedEventId(event.id)}
                      className="absolute left-1 right-1 rounded-lg px-2 py-1 text-[11px] font-bold text-white border transition-all hover:scale-[1.01] hover:shadow-md z-10 cursor-pointer shadow-sm"
                      style={{
                        ...pos,
                        backgroundColor: event.color || "var(--primary)",
                        borderColor: event.color || "var(--primary)",
                      }}
                    >
                      <div className="truncate">{event.title}</div>
                      <div className="text-[9px] opacity-90 font-medium mt-0.5">
                        {format(new Date(event.startTime), "h:mm a")}
                      </div>
                    </div>
                  )
                })}
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

