export function GoalDialog({ open, onOpenChange, goal }: GoalDialogProps) {
  const createGoal = useCreateGoalMutation()
  const updateGoal = useUpdateGoalMutation()

  const { data: projects } = useProjects()
  const { data: tasks } = useTasks()

  const [title, setTitle] = React.useState("")
  const [description, setDescription] = React.useState("")
  const [category, setCategory] = React.useState("PERSONAL")
  const [priority, setPriority] = React.useState("MEDIUM")
  const [targetDate, setTargetDate] = React.useState("")
  const [color, setColor] = React.useState("#3b82f6")
  const [notes, setNotes] = React.useState("")
  const [tags, setTags] = React.useState("")
  const [projectId, setProjectId] = React.useState("")
  const [taskId, setTaskId] = React.useState("")

  // Progress Type: "milestones" | "numeric" | "manual"
  const [progressType, setProgressType] = React.useState<"milestones" | "numeric" | "manual">("manual")

  // Numeric tracking fields
  const [targetValue, setTargetValue] = React.useState("")
  const [currentValue, setCurrentValue] = React.useState("")
  const [units, setUnits] = React.useState("")

  // Milestones
  const [milestones, setMilestones] = React.useState<{ title: string; dueDate?: string }[]>([])
  const [newMilestoneTitle, setNewMilestoneTitle] = React.useState("")

  // Initialize fields if editing
  React.useEffect(() => {
    if (goal) {
      setTitle(goal.title)
      setDescription(goal.description || "")
      setCategory(goal.category)
      setPriority(goal.priority)
      setTargetDate(goal.targetDate ? goal.targetDate.split("T")[0] : "")
      setColor(goal.color)
      setNotes(goal.notes || "")
      setTags(goal.tags || "")
      setProjectId(goal.projectId || "")
      setTaskId(goal.taskId || "")

      if (goal.targetValue !== null) {
        setProgressType("numeric")
        setTargetValue(goal.targetValue.toString())
        setCurrentValue(goal.currentValue.toString())
        setUnits(goal.units || "")
      } else if (goal.milestones && goal.milestones.length > 0) {
        setProgressType("milestones")
        setMilestones(goal.milestones.map(m => ({ title: m.title, dueDate: m.dueDate ? m.dueDate.split("T")[0] : undefined })))
      } else {
        setProgressType("manual")
      }
    } else {
      // Reset
      setTitle("")
      setDescription("")
      setCategory("PERSONAL")
      setPriority("MEDIUM")
      setTargetDate("")
      setColor("#3b82f6")
      setNotes("")
      setTags("")
      setProjectId("")
      setTaskId("")
      setProgressType("manual")
      setTargetValue("")
      setCurrentValue("")
      setUnits("")
      setMilestones([])
    }
  }, [goal, open])

  const handleAddMilestone = () => {
    if (!newMilestoneTitle.trim()) return
    setMilestones([...milestones, { title: newMilestoneTitle.trim() }])
    setNewMilestoneTitle("")
  }

  const handleRemoveMilestone = (index: number) => {
    setMilestones(milestones.filter((_, i) => i !== index))
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim()) return

    const data: any = {
      title: title.trim(),
      description: description.trim() || null,
      category,
      priority,
      color,
      notes: notes.trim() || null,
      tags: tags.trim() || null,
      projectId: projectId || null,
      taskId: taskId || null,
      targetDate: targetDate ? new Date(targetDate).toISOString() : null,
    }

    if (progressType === "numeric") {
      data.targetValue = targetValue ? parseFloat(targetValue) : null
      data.currentValue = currentValue ? parseFloat(currentValue) : 0
      data.units = units.trim() || null
    } else if (progressType === "milestones") {
      data.milestones = milestones
      data.targetValue = null
      data.currentValue = 0
      data.units = null
    } else {
      data.targetValue = null
      data.currentValue = 0
      data.units = null
    }

    if (goal) {
      updateGoal.mutate(
        { id: goal.id, ...data },
        {
          onSuccess: () => onOpenChange(false),
        }
      )
    } else {
      createGoal.mutate(data, {
        onSuccess: () => onOpenChange(false),
      })
    }
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-xl max-h-[90vh] overflow-y-auto p-6 bg-card/95 backdrop-blur-xl border shadow-2xl rounded-2xl">
        <DialogHeader>
          <DialogTitle className="text-2xl font-bold tracking-tight flex items-center gap-2">
            <Target className="size-6 text-primary animate-pulse" />
            {goal ? "Edit Goal" : "Create New Goal"}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 mt-4">
          <div className="space-y-2">
            <Label htmlFor="title" className="text-sm font-semibold">Goal Title</Label>
            <Input
              id="title"
              placeholder="e.g., Read 12 Books"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              required
              className="rounded-xl border-input focus:ring-2 focus:ring-primary"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="description" className="text-sm font-semibold">Description</Label>
            <Textarea
              id="description"
              placeholder="Outline what you want to achieve..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="rounded-xl border-input min-h-[80px]"
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Category</Label>
              <select
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                className="w-full h-10 px-3 py-1 bg-background border border-input rounded-xl text-sm outline-none focus:ring-2 focus:ring-primary"
              >
                {CATEGORIES.map((c) => (
                  <option key={c.value} value={c.value}>
                    {c.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <Label className="text-sm font-semibold">Priority</Label>
              <select
                value={priority}
                onChange={(e) => setPriority(e.target.value)}
                className="w-full h-10 px-3 py-1 bg-background border border-input rounded-xl text-sm outline-none focus:ring-2 focus:ring-primary"
              >
                {PRIORITIES.map((p) => (
                  <option key={p.value} value={p.value}>
                    {p.label}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="targetDate" className="text-sm font-semibold">Target Date</Label>
              <Input
                id="targetDate"
                type="date"
                value={targetDate}
                onChange={(e) => setTargetDate(e.target.value)}
                className="rounded-xl border-input"
              />
            </div>

            <div className="space-y-2">
              <Label className="text-sm font-semibold">Goal Color</Label>
              <div className="flex gap-2 items-center flex-wrap h-10">
                {PRESET_COLORS.map((c) => (
                  <button
                    key={c}
                    type="button"
                    onClick={() => setColor(c)}
                    className="size-6 rounded-full border border-white/20 transition-transform hover:scale-125 focus:outline-none"
                    style={{
                      backgroundColor: c,
                      boxShadow: color === c ? `0 0 0 2px white, 0 0 0 4px ${c}` : "none",
                    }}
                  />
                ))}
              </div>
            </div>
          </div>

          {/* Progress Type Selection */}
          <div className="space-y-3 p-4 bg-muted/30 border rounded-2xl">
            <Label className="text-sm font-semibold">Progress Tracking Method</Label>
            <div className="grid grid-cols-3 gap-2">
              <button
                type="button"
                onClick={() => setProgressType("manual")}
                className={`py-2 px-3 text-xs font-semibold rounded-xl border transition-all ${
                  progressType === "manual"
                    ? "bg-primary text-primary-foreground border-primary shadow-sm"
                    : "bg-background hover:bg-muted"
                }`}
              >
                Manual %
              </button>
              <button
                type="button"
                onClick={() => setProgressType("numeric")}
                className={`py-2 px-3 text-xs font-semibold rounded-xl border transition-all ${
                  progressType === "numeric"
                    ? "bg-primary text-primary-foreground border-primary shadow-sm"
                    : "bg-background hover:bg-muted"
                }`}
              >
                Numeric Target
              </button>
              <button
                type="button"
                onClick={() => setProgressType("milestones")}
                className={`py-2 px-3 text-xs font-semibold rounded-xl border transition-all ${
                  progressType === "milestones"
                    ? "bg-primary text-primary-foreground border-primary shadow-sm"
                    : "bg-background hover:bg-muted"
                }`}
              >
                Milestones
              </button>
            </div>

            {progressType === "numeric" && (
              <div className="grid grid-cols-3 gap-2 pt-2 animate-in fade-in duration-300">
                <div className="space-y-1">
                  <Label className="text-[10px] uppercase font-bold">Current</Label>
                  <Input
                    type="number"
                    value={currentValue}
                    onChange={(e) => setCurrentValue(e.target.value)}
                    placeholder="0"
                    className="h-8 rounded-lg"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-[10px] uppercase font-bold">Target</Label>
                  <Input
                    type="number"
                    value={targetValue}
                    onChange={(e) => setTargetValue(e.target.value)}
                    placeholder="100"
                    className="h-8 rounded-lg"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-[10px] uppercase font-bold">Units</Label>
                  <Input
                    value={units}
                    onChange={(e) => setUnits(e.target.value)}
                    placeholder="e.g. miles"
                    className="h-8 rounded-lg"
                  />
                </div>
              </div>
            )}

            {progressType === "milestones" && (
              <div className="space-y-2 pt-2 animate-in fade-in duration-300">
                <Label className="text-xs font-semibold">Milestones List</Label>
                <div className="flex gap-2">
                  <Input
                    placeholder="New milestone..."
                    value={newMilestoneTitle}
                    onChange={(e) => setNewMilestoneTitle(e.target.value)}
                    className="h-9 rounded-xl"
                  />
                  <Button type="button" onClick={handleAddMilestone} size="sm" className="rounded-xl h-9">
                    <Plus className="size-4" />
                  </Button>
                </div>
                <ul className="space-y-1.5 max-h-36 overflow-y-auto pr-1 mt-2">
                  {milestones.map((m, index) => (
                    <li key={index} className="flex items-center justify-between p-2 rounded-xl bg-background border text-xs">
                      <span className="truncate pr-4 font-medium">{m.title}</span>
                      <button
                        type="button"
                        onClick={() => handleRemoveMilestone(index)}
                        className="text-muted-foreground hover:text-destructive transition-colors"
                      >
                        <Trash2 className="size-3.5" />
                      </button>
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </div>

          {/* Integrations */}
          <div className="space-y-4 p-4 bg-muted/20 border rounded-2xl">
            <h4 className="text-xs font-bold uppercase tracking-wider text-muted-foreground flex items-center gap-1.5">
              <Layers className="size-3.5" />
              Integrations (Link to Workspace)
            </h4>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label className="text-xs font-medium">Link Project</Label>
                <select
                  value={projectId}
                  onChange={(e) => setProjectId(e.target.value)}
                  className="w-full h-9 px-3 py-1 bg-background border border-input rounded-xl text-xs outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="">None</option>
                  {projects?.map((p: any) => (
                    <option key={p.id} value={p.id}>
                      {p.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <Label className="text-xs font-medium">Link Task</Label>
                <select
                  value={taskId}
                  onChange={(e) => setTaskId(e.target.value)}
                  className="w-full h-9 px-3 py-1 bg-background border border-input rounded-xl text-xs outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="">None</option>
                  {tasks?.map((t: any) => (
                    <option key={t.id} value={t.id}>
                      {t.title}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          <DialogFooter className="pt-4 border-t">
            <Button
              type="button"
              variant="ghost"
              onClick={() => onOpenChange(false)}
              className="rounded-xl"
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={createGoal.isPending || updateGoal.isPending}
              className="rounded-xl shadow-lg px-6"
            >
              {goal ? "Save Changes" : "Create Goal"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import * as React from "react"
import { motion, AnimatePresence } from "framer-motion"
import {
  useGetGoalsQuery,
  useUpdateGoalMutation,
  useDeleteGoalMutation,
  useUpdateMilestoneMutation,
  Goal,
  Milestone,
} from "@/hooks/use-goals-queries"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Progress } from "@/components/ui/progress"
import { GoalDialog } from "./goal-dialog"
import {
  Target,
  Plus,
  Search,
  MoreVertical,
  Calendar,
  Layers,
  CheckSquare,
  AlertCircle,
  FolderOpen,
  Filter,
  CheckCircle2,
} from "lucide-react"

export function GoalsList() {
  const [search, setSearch] = React.useState("")
  const [status, setStatus] = React.useState("ACTIVE")
  const [category, setCategory] = React.useState("ALL")
  const [priority, setPriority] = React.useState("ALL")

  const { data: goals, isLoading, isError } = useGetGoalsQuery({
    search,
    status,
    category,
    priority,
  })

  const updateGoal = useUpdateGoalMutation()
  const deleteGoal = useDeleteGoalMutation()
  const updateMilestone = useUpdateMilestoneMutation()

  const [dialogOpen, setDialogOpen] = React.useState(false)
  const [editingGoal, setEditingGoal] = React.useState<Goal | null>(null)
  const [activeMenuId, setActiveMenuId] = React.useState<string | null>(null)

  const handleEdit = (goal: Goal) => {
    setEditingGoal(goal)
    setDialogOpen(true)
    setActiveMenuId(null)
  }

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this goal?")) {
      deleteGoal.mutate(id)
    }
    setActiveMenuId(null)
  }

  const handleToggleMilestone = (goalId: string, milestone: Milestone) => {
    updateMilestone.mutate({
      goalId,
      milestoneId: milestone.id,
      isCompleted: !milestone.isCompleted,
    })
  }

  const handleManualProgressChange = (goal: Goal, amount: number) => {
    const newProgress = Math.min(100, Math.max(0, goal.progress + amount))
    updateGoal.mutate({
      id: goal.id,
      progress: newProgress,
    })
  }

  const handleNumericValueChange = (goal: Goal, isIncrement: boolean) => {
    const step = 1
    const newCurrent = isIncrement 
      ? goal.currentValue + step 
      : Math.max(0, goal.currentValue - step)

    updateGoal.mutate({
      id: goal.id,
      currentValue: newCurrent,
    })
  }

  // Close menus when clicking outside
  React.useEffect(() => {
    const handleOutsideClick = () => setActiveMenuId(null)
    document.addEventListener("click", handleOutsideClick)
    return () => document.removeEventListener("click", handleOutsideClick)
  }, [])

  return (
    <div className="space-y-6">
      {/* Search and Filters */}
      <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center bg-card/40 p-4 border rounded-2xl">
        <div className="relative w-full md:max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
          <Input
            placeholder="Search goals..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9 rounded-xl border-input bg-background/50"
          />
        </div>

        <div className="flex flex-wrap gap-2 items-center w-full md:w-auto">
          <div className="flex items-center gap-1.5 text-xs text-muted-foreground mr-2">
            <Filter className="size-3.5" />
            Filters:
          </div>

          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="h-9 px-3 bg-background border border-input rounded-xl text-xs outline-none focus:ring-1 focus:ring-primary"
          >
            <option value="ACTIVE">Active Goals</option>
            <option value="COMPLETED">Completed Goals</option>
            <option value="ARCHIVED">Archived Goals</option>
            <option value="ALL">All Goals</option>
          </select>

          <select
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="h-9 px-3 bg-background border border-input rounded-xl text-xs outline-none focus:ring-1 focus:ring-primary"
          >
            <option value="ALL">All Categories</option>
            <option value="PERSONAL">Personal</option>
            <option value="WORK">Work</option>
            <option value="STUDY">Study</option>
            <option value="HEALTH">Health</option>
            <option value="FITNESS">Fitness</option>
            <option value="FINANCIAL">Financial</option>
            <option value="READING">Reading</option>
            <option value="LEARNING">Learning</option>
          </select>

          <select
            value={priority}
            onChange={(e) => setPriority(e.target.value)}
            className="h-9 px-3 bg-background border border-input rounded-xl text-xs outline-none focus:ring-1 focus:ring-primary"
          >
            <option value="ALL">All Priorities</option>
            <option value="LOW">Low</option>
            <option value="MEDIUM">Medium</option>
            <option value="HIGH">High</option>
            <option value="URGENT">Urgent</option>
          </select>

          <Button
            onClick={() => {
              setEditingGoal(null)
              setDialogOpen(true)
            }}
            className="rounded-xl ml-auto md:ml-0"
            size="sm"
          >
            <Plus className="size-4 mr-1.5" />
            New Goal
          </Button>
        </div>
      </div>

      {/* Goals Grid */}
      {isLoading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-64 rounded-2xl border bg-card/40 animate-pulse" />
          ))}
        </div>
      ) : isError || !goals ? (
        <div className="text-center p-12 border border-dashed rounded-3xl">
          <AlertCircle className="size-12 text-destructive mx-auto mb-4" />
          <h3 className="text-lg font-semibold">Error Loading Goals</h3>
          <p className="text-muted-foreground text-sm">Please try again later.</p>
        </div>
      ) : goals.length === 0 ? (
        <div className="text-center p-16 border border-dashed rounded-3xl bg-card/10">
          <Target className="size-16 text-muted-foreground/30 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-foreground">No Goals Found</h3>
          <p className="text-muted-foreground text-sm mt-1 mb-6">Create a goal to start mapping your milestones.</p>
          <Button onClick={() => setDialogOpen(true)} className="rounded-xl">
            Create First Goal
          </Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <AnimatePresence>
            {goals.map((goal) => (
              <motion.div
                key={goal.id}
                layout
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95 }}
                transition={{ duration: 0.2 }}
                className="relative flex flex-col justify-between border bg-card p-6 rounded-2xl shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden group"
              >
                {/* Background Accent */}
                <div
                  className="absolute top-0 left-0 w-1.5 h-full opacity-80"
                  style={{ backgroundColor: goal.color }}
                />

                <div className="space-y-4">
                  {/* Goal Header */}
                  <div className="flex justify-between items-start gap-4">
                    <div className="flex flex-wrap gap-1.5">
                      <span className="text-[10px] uppercase font-bold tracking-wider px-2 py-0.5 rounded-full bg-muted text-muted-foreground">
                        {goal.category}
                      </span>
                      <span
                        className={`text-[10px] uppercase font-bold tracking-wider px-2 py-0.5 rounded-full ${
                          goal.priority === "URGENT"
                            ? "bg-rose-500/10 text-rose-500"
                            : goal.priority === "HIGH"
                            ? "bg-amber-500/10 text-amber-500"
                            : "bg-muted text-muted-foreground"
                        }`}
                      >
                        {goal.priority}
                      </span>
                    </div>

                    {/* Menu Button */}
                    <div className="relative">
                      <Button
                        variant="ghost"
                        size="icon-sm"
                        onClick={(e) => {
                          e.stopPropagation()
                          setActiveMenuId(activeMenuId === goal.id ? null : goal.id)
                        }}
                        className="rounded-full hover:bg-muted"
                      >
                        <MoreVertical className="size-4 text-muted-foreground" />
                      </Button>

                      {activeMenuId === goal.id && (
                        <div className="absolute right-0 mt-1 w-32 bg-popover border shadow-lg rounded-xl z-20 py-1.5 animate-in fade-in zoom-in-95 duration-100">
                          <button
                            onClick={() => handleEdit(goal)}
                            className="w-full text-left px-3 py-1.5 text-xs hover:bg-muted font-medium text-foreground"
                          >
                            Edit Goal
                          </button>
                          <button
                            onClick={() => handleDelete(goal.id)}
                            className="w-full text-left px-3 py-1.5 text-xs hover:bg-muted font-medium text-destructive"
                          >
                            Delete
                          </button>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Goal Info */}
                  <div>
                    <h3 className="font-bold text-lg text-foreground group-hover:text-primary transition-colors duration-200">
                      {goal.title}
                    </h3>
                    {goal.description && (
                      <p className="text-xs text-muted-foreground mt-1 line-clamp-2">
                        {goal.description}
                      </p>
                    )}
                  </div>

                  {/* Goal Progress Section */}
                  <div className="space-y-2 pt-2">
                    <div className="flex items-center justify-between text-xs font-semibold">
                      <span className="text-muted-foreground">Progress</span>
                      <span style={{ color: goal.color }} className="font-bold">
                        {goal.progress}%
                      </span>
                    </div>
                    <Progress
                      value={goal.progress}
                      className="h-2 rounded-full bg-muted"
                      indicatorStyle={{ backgroundColor: goal.color }}
                    />
                  </div>

                  {/* Numeric / Milestones Details */}
                  {goal.targetValue !== null ? (
                    <div className="flex items-center justify-between p-2.5 bg-muted/30 border rounded-xl">
                      <div className="text-xs">
                        <span className="font-bold text-foreground">{goal.currentValue}</span>
                        <span className="text-muted-foreground"> / {goal.targetValue} {goal.units || ""}</span>
                      </div>
                      <div className="flex gap-1">
                        <Button
                          variant="outline"
                          size="icon-xs"
                          onClick={() => handleNumericValueChange(goal, false)}
                          className="size-6 rounded-md"
                        >
                          -
                        </Button>
                        <Button
                          variant="outline"
                          size="icon-xs"
                          onClick={() => handleNumericValueChange(goal, true)}
                          className="size-6 rounded-md"
                        >
                          +
                        </Button>
                      </div>
                    </div>
                  ) : goal.milestones && goal.milestones.length > 0 ? (
                    <div className="space-y-1.5 pt-2">
                      <div className="text-[10px] uppercase font-bold tracking-wider text-muted-foreground">
                        Milestones ({goal.milestones.filter(m => m.isCompleted).length}/{goal.milestones.length})
                      </div>
                      <ul className="space-y-1 max-h-24 overflow-y-auto pr-1">
                        {goal.milestones.map((m) => (
                          <li
                            key={m.id}
                            onClick={() => handleToggleMilestone(goal.id, m)}
                            className="flex items-center gap-2 text-xs font-medium py-1 px-2 rounded-lg hover:bg-muted/50 cursor-pointer transition-colors"
                          >
                            <CheckCircle2
                              className={`size-4 shrink-0 transition-colors ${
                                m.isCompleted
                                  ? "text-emerald-500 fill-emerald-500/10"
                                  : "text-muted-foreground/40"
                              }`}
                            />
                            <span className={m.isCompleted ? "line-through text-muted-foreground" : "text-foreground"}>
                              {m.title}
                            </span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  ) : (
                    <div className="flex items-center justify-between p-2.5 bg-muted/30 border rounded-xl text-xs font-medium">
                      <span className="text-muted-foreground">Adjust Progress:</span>
                      <div className="flex gap-1">
                        <Button
                          variant="outline"
                          size="icon-xs"
                          onClick={() => handleManualProgressChange(goal, -10)}
                          className="h-6 px-1.5 text-[10px] rounded-md"
                        >
                          -10%
                        </Button>
                        <Button
                          variant="outline"
                          size="icon-xs"
                          onClick={() => handleManualProgressChange(goal, 10)}
                          className="h-6 px-1.5 text-[10px] rounded-md"
                        >
                          +10%
                        </Button>
                      </div>
                    </div>
                  )}
                </div>

                {/* Footer details */}
                <div className="flex items-center justify-between border-t pt-3 mt-4 text-[10px] font-semibold text-muted-foreground">
                  <div className="flex items-center gap-1.5">
                    <Calendar className="size-3.5" />
                    <span>
                      {goal.targetDate
                        ? new Date(goal.targetDate).toLocaleDateString(undefined, {
                            month: "short",
                            day: "numeric",
                            year: "numeric",
                          })
                        : "No deadline"}
                    </span>
                  </div>

                  <div className="flex gap-2">
                    {goal.project && (
                      <div className="flex items-center gap-1 bg-primary/5 px-1.5 py-0.5 rounded border border-primary/10">
                        <FolderOpen className="size-3 text-primary" />
                        <span className="truncate max-w-[60px]">{goal.project.name}</span>
                      </div>
                    )}
                    {goal.task && (
                      <div className="flex items-center gap-1 bg-muted px-1.5 py-0.5 rounded border">
                        <CheckSquare className="size-3 text-muted-foreground" />
                        <span className="truncate max-w-[60px]">{goal.task.title}</span>
                      </div>
                    )}
                  </div>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      )}

      {/* Goal Creation Dialog */}
      <GoalDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        goal={editingGoal}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Label } from "@/components/ui/label"
import { useCreateHabitMutation, useUpdateHabitMutation, Habit } from "@/hooks/use-goals-queries"
import { useProjects } from "@/hooks/use-projects-queries"
import { useTasks } from "@/hooks/use-tasks-queries"
import { Activity, Plus, Minus, Layers } from "lucide-react"

interface HabitDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  habit?: Habit | null // If passed, we are editing
}

const FREQUENCIES = [
  { value: "DAILY", label: "Daily" },
  { value: "WEEKLY", label: "Weekly" },
  { value: "MONTHLY", label: "Monthly" },
  { value: "CUSTOM", label: "Custom Days" },
]

const DAYS_OF_WEEK = [
  { value: "1", label: "Mon" },
  { value: "2", label: "Tue" },
  { value: "3", label: "Wed" },
  { value: "4", label: "Thu" },
  { value: "5", label: "Fri" },
  { value: "6", label: "Sat" },
  { value: "0", label: "Sun" },
]

const PRESET_COLORS = [
  "#f59e0b", // Amber/Orange
  "#ef4444", // Red
  "#3b82f6", // Blue
  "#10b981", // Green
  "#8b5cf6", // Purple
  "#ec4899", // Pink
  "#06b6d4", // Cyan
  "#6b7280", // Gray
]

export function HabitDialog({ open, onOpenChange, habit }: HabitDialogProps) {
  const createHabit = useCreateHabitMutation()
  const updateHabit = useUpdateHabitMutation()

  const { data: projects } = useProjects()
  const { data: tasks } = useTasks()

  const [title, setTitle] = React.useState("")
  const [description, setDescription] = React.useState("")
  const [frequency, setFrequency] = React.useState("DAILY")
  const [customDays, setCustomDays] = React.useState<string[]>([])
  const [targetCount, setTargetCount] = React.useState(1)
  const [isNegative, setIsNegative] = React.useState(false)
  const [color, setColor] = React.useState("#f59e0b")
  const [icon, setIcon] = React.useState("Activity")
  const [projectId, setProjectId] = React.useState("")
  const [taskId, setTaskId] = React.useState("")

  // Initialize fields if editing
  React.useEffect(() => {
    if (habit) {
      setTitle(habit.title)
      setDescription(habit.description || "")
      setFrequency(habit.frequency)
      setCustomDays(habit.customDays ? habit.customDays.split(",") : [])
      setTargetCount(habit.targetCount)
      setIsNegative(habit.isNegative)
      setColor(habit.color)
      setIcon(habit.icon)
      setProjectId(habit.projectId || "")
      setTaskId(habit.taskId || "")
    } else {
      // Reset
      setTitle("")
      setDescription("")
      setFrequency("DAILY")
      setCustomDays([])
      setTargetCount(1)
      setIsNegative(false)
      setColor("#f59e0b")
      setIcon("Activity")
      setProjectId("")
      setTaskId("")
    }
  }, [habit, open])

  const toggleDay = (day: string) => {
    if (customDays.includes(day)) {
      setCustomDays(customDays.filter((d) => d !== day))
    } else {
      setCustomDays([...customDays, day].sort())
    }
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim()) return

    const data: any = {
      title: title.trim(),
      description: description.trim() || null,
      frequency,
      customDays: frequency === "CUSTOM" ? customDays.join(",") : null,
      targetCount: parseInt(targetCount.toString()) || 1,
      isNegative,
      color,
      icon,
      projectId: projectId || null,
      taskId: taskId || null,
    }

    if (habit) {
      updateHabit.mutate(
        { id: habit.id, ...data },
        {
          onSuccess: () => onOpenChange(false),
        }
      )
    } else {
      createHabit.mutate(data, {
        onSuccess: () => onOpenChange(false),
      })
    }
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md max-h-[90vh] overflow-y-auto p-6 bg-card/95 backdrop-blur-xl border shadow-2xl rounded-2xl">
        <DialogHeader>
          <DialogTitle className="text-2xl font-bold tracking-tight flex items-center gap-2">
            <Activity className="size-6 text-primary animate-pulse" />
            {habit ? "Edit Habit" : "Create New Habit"}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 mt-4">
          <div className="space-y-2">
            <Label htmlFor="title" className="text-sm font-semibold">Habit Title</Label>
            <Input
              id="title"
              placeholder="e.g., Morning Workout"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              required
              className="rounded-xl border-input focus:ring-2 focus:ring-primary"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="description" className="text-sm font-semibold">Description</Label>
            <Textarea
              id="description"
              placeholder="Write a short cue or reminder..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="rounded-xl border-input min-h-[60px]"
            />
          </div>

          {/* Habit Type (Positive vs Negative) */}
          <div className="space-y-2">
            <Label className="text-sm font-semibold">Habit Type</Label>
            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => setIsNegative(false)}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border font-semibold transition-all text-sm ${
                  !isNegative
                    ? "bg-emerald-500/10 text-emerald-500 border-emerald-500 shadow-sm"
                    : "bg-background hover:bg-muted"
                }`}
              >
                <Plus className="size-4" />
                Positive (Build)
              </button>
              <button
                type="button"
                onClick={() => setIsNegative(true)}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border font-semibold transition-all text-sm ${
                  isNegative
                    ? "bg-rose-500/10 text-rose-500 border-rose-500 shadow-sm"
                    : "bg-background hover:bg-muted"
                }`}
              >
                <Minus className="size-4" />
                Negative (Break)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Frequency</Label>
              <select
                value={frequency}
                onChange={(e) => setFrequency(e.target.value)}
                className="w-full h-10 px-3 py-1 bg-background border border-input rounded-xl text-sm outline-none focus:ring-2 focus:ring-primary"
              >
                {FREQUENCIES.map((f) => (
                  <option key={f.value} value={f.value}>
                    {f.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="targetCount" className="text-sm font-semibold">Daily Target Count</Label>
              <Input
                id="targetCount"
                type="number"
                min={1}
                value={targetCount}
                onChange={(e) => setTargetCount(parseInt(e.target.value) || 1)}
                className="rounded-xl border-input"
              />
            </div>
          </div>

          {frequency === "CUSTOM" && (
            <div className="space-y-2 p-3 bg-muted/30 border rounded-xl animate-in slide-in-from-top-2 duration-300">
              <Label className="text-xs font-semibold">Select Days</Label>
              <div className="flex flex-wrap gap-1.5 mt-1">
                {DAYS_OF_WEEK.map((d) => {
                  const isSelected = customDays.includes(d.value)
                  return (
                    <button
                      key={d.value}
                      type="button"
                      onClick={() => toggleDay(d.value)}
                      className={`h-8 px-2.5 rounded-lg text-xs font-semibold border transition-all ${
                        isSelected
                          ? "bg-primary text-primary-foreground border-primary"
                          : "bg-background hover:bg-muted"
                      }`}
                    >
                      {d.label}
                    </button>
                  )
                })}
              </div>
            </div>
          )}

          <div className="space-y-2">
            <Label className="text-sm font-semibold">Theme Color</Label>
            <div className="flex gap-2 items-center flex-wrap h-10">
              {PRESET_COLORS.map((c) => (
                <button
                  key={c}
                  type="button"
                  onClick={() => setColor(c)}
                  className="size-6 rounded-full border border-white/20 transition-transform hover:scale-125 focus:outline-none"
                  style={{
                    backgroundColor: c,
                    boxShadow: color === c ? `0 0 0 2px white, 0 0 0 4px ${c}` : "none",
                  }}
                />
              ))}
            </div>
          </div>

          {/* Integrations */}
          <div className="space-y-4 p-4 bg-muted/20 border rounded-2xl">
            <h4 className="text-xs font-bold uppercase tracking-wider text-muted-foreground flex items-center gap-1.5">
              <Layers className="size-3.5" />
              Integrations (Link to Workspace)
            </h4>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label className="text-xs font-medium">Link Project</Label>
                <select
                  value={projectId}
                  onChange={(e) => setProjectId(e.target.value)}
                  className="w-full h-9 px-3 py-1 bg-background border border-input rounded-xl text-xs outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="">None</option>
                  {projects?.map((p: any) => (
                    <option key={p.id} value={p.id}>
                      {p.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <Label className="text-xs font-medium">Link Task</Label>
                <select
                  value={taskId}
                  onChange={(e) => setTaskId(e.target.value)}
                  className="w-full h-9 px-3 py-1 bg-background border border-input rounded-xl text-xs outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="">None</option>
                  {tasks?.map((t: any) => (
                    <option key={t.id} value={t.id}>
                      {t.title}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          <DialogFooter className="pt-4 border-t">
            <Button
              type="button"
              variant="ghost"
              onClick={() => onOpenChange(false)}
              className="rounded-xl"
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={createHabit.isPending || updateHabit.isPending}
              className="rounded-xl shadow-lg px-6"
            >
              {habit ? "Save Changes" : "Create Habit"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import * as React from "react"
import { useGetHabitsQuery } from "@/hooks/use-goals-queries"
import { Calendar as CalendarIcon, Info } from "lucide-react"

export function HabitsCalendar() {
  const { data: habits } = useGetHabitsQuery()

  // Generate last 180 days grouped by weeks (about 26 weeks)
  const calendarGrid = React.useMemo(() => {
    const grid: Date[][] = []
    const today = new Date()

    // Find the starting day: 24 weeks ago, aligned to Monday (1)
    const startDate = new Date()
    startDate.setDate(today.getDate() - 24 * 7)
    const startDayOfWeek = startDate.getDay() // 0 is Sun, 1 is Mon
    const daysToSubtract = startDayOfWeek === 0 ? 6 : startDayOfWeek - 1
    startDate.setDate(startDate.getDate() - daysToSubtract)

    let current = new Date(startDate)
    let currentWeek: Date[] = []

    while (current <= today) {
      currentWeek.push(new Date(current))

      if (currentWeek.length === 7) {
        grid.push(currentWeek)
        currentWeek = []
      }

      current.setDate(current.getDate() + 1)
    }

    if (currentWeek.length > 0) {
      // Pad the last week if it's incomplete
      while (currentWeek.length < 7) {
        const nextDay = new Date(currentWeek[currentWeek.length - 1])
        nextDay.setDate(nextDay.getDate() + 1)
        currentWeek.push(nextDay)
      }
      grid.push(currentWeek)
    }

    return grid
  }, [])

  // Helper to format a local Date object as YYYY-MM-DD without timezone shifting
  const getLocalYYYYMMDD = (date: Date) => {
    const year = date.getFullYear()
    const month = String(date.getMonth() + 1).padStart(2, "0")
    const day = String(date.getDate()).padStart(2, "0")
    return `${year}-${month}-${day}`
  }

  // Calculate completions per day
  const completionsMap = React.useMemo(() => {
    const map: Record<string, number> = {}
    if (!habits) return map

    habits.forEach((habit) => {
      habit.history.forEach((hist) => {
        if (hist.status === "COMPLETED") {
          // Keep the raw YYYY-MM-DD string from database
          const dateStr = hist.date.toString().split("T")[0]
          map[dateStr] = (map[dateStr] || 0) + 1
        }
      })
    })

    return map
  }, [habits])

  // Get color based on completion count
  const getCellColor = (count: number) => {
    if (count === 0) return "bg-muted/20 dark:bg-muted/10 hover:bg-muted/40"
    if (count === 1) return "bg-primary/20 hover:bg-primary/30 text-primary-foreground"
    if (count === 2) return "bg-primary/40 hover:bg-primary/50 text-primary-foreground"
    if (count === 3) return "bg-primary/70 hover:bg-primary/80 text-primary-foreground"
    return "bg-primary hover:bg-primary/95 text-primary-foreground"
  }

  // Compute month labels with their column index offsets
  const monthLabels = React.useMemo(() => {
    const labels: { index: number; label: string }[] = []
    let lastMonth = -1

    calendarGrid.forEach((week, index) => {
      // Check the middle day of the week to avoid boundary edge cases
      const middleDay = week[3]
      const currentMonth = middleDay.getMonth()

      if (currentMonth !== lastMonth) {
        const monthName = middleDay.toLocaleDateString("en-US", { month: "short" })
        labels.push({ index, label: monthName })
        lastMonth = currentMonth
      }
    })

    return labels
  }, [calendarGrid])

  return (
    <div className="border bg-card p-6 rounded-2xl shadow-sm">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h3 className="font-bold text-lg text-foreground flex items-center gap-2">
            <CalendarIcon className="size-5 text-primary" />
            Consistency Heatmap
          </h3>
          <p className="text-xs text-muted-foreground mt-0.5">
            Your habit completion density over the last 6 months.
          </p>
        </div>

        {/* Legend */}
        <div className="flex items-center gap-1.5 text-[10px] font-semibold text-muted-foreground">
          <span>Less</span>
          <div className="size-2.5 rounded-sm bg-muted/20" />
          <div className="size-2.5 rounded-sm bg-primary/20" />
          <div className="size-2.5 rounded-sm bg-primary/40" />
          <div className="size-2.5 rounded-sm bg-primary/70" />
          <div className="size-2.5 rounded-sm bg-primary" />
          <span>More</span>
        </div>
      </div>

      <div className="overflow-x-auto pb-2 -mx-6 px-6">
        <div className="flex flex-col min-w-[500px]">
          {/* Month Labels Row */}
          <div className="flex text-[9px] font-extrabold text-muted-foreground/50 h-4 mb-1 ml-8 relative select-none">
            {monthLabels.map((ml) => (
              <span
                key={ml.index}
                className="absolute"
                style={{
                  left: `calc(${ml.index} * 1rem)`, // 1rem = 16px which matches our column spacing (size-3 + gap-1)
                }}
              >
                {ml.label}
              </span>
            ))}
          </div>

          <div className="flex gap-1">
            {/* Weekday Labels (Aligned perfectly to the 7 rows using inline gridTemplateRows) */}
            <div 
              className="grid text-[9px] font-extrabold text-muted-foreground pr-2 h-[108px] select-none"
              style={{ gridTemplateRows: "repeat(7, minmax(0, 1fr))" }}
            >
              <span className="row-start-1 flex items-center">Mon</span>
              <span className="row-start-3 flex items-center">Wed</span>
              <span className="row-start-5 flex items-center">Fri</span>
              <span className="row-start-7 flex items-center">Sun</span>
            </div>

            {/* Heatmap Columns */}
            <div className="flex gap-1">
              {calendarGrid.map((week, weekIndex) => (
                <div key={weekIndex} className="flex flex-col gap-1">
                  {week.map((day) => {
                    const dateStr = getLocalYYYYMMDD(day)
                    const count = completionsMap[dateStr] || 0
                    const isFuture = day > new Date()
                    const formattedDate = day.toLocaleDateString(undefined, {
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    })

                    return (
                      <div
                        key={dateStr}
                        title={isFuture ? undefined : `${formattedDate}: ${count} habits completed`}
                        className={`size-3 rounded-sm transition-all duration-200 ${
                          isFuture 
                            ? "bg-muted/20 dark:bg-muted/10 opacity-30 cursor-default" 
                            : getCellColor(count)
                        }`}
                      />
                    )
                  })}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="flex items-start gap-2 mt-4 p-3 bg-muted/30 border border-border/50 rounded-xl text-xs text-muted-foreground">
        <Info className="size-4 text-primary shrink-0 mt-0.5" />
        <span>
          Habit consistency scores update in real time. Completed items boost your weekly consistency score and extend your streak!
        </span>
      </div>
    </div>
  )
}

