  useLogHabitMutation,
  Habit,
} from "@/hooks/use-goals-queries"
import { Button } from "@/components/ui/button"
import { HabitDialog } from "./habit-dialog"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Activity,
  Plus,
  Flame,
  Check,
  MoreVertical,
  Calendar,
  AlertCircle,
  Pause,
  Play,
  RotateCcw,
  Folder,
  CheckSquare,
  Trophy,
  TrendingUp,
