import { useUpdateTask, useDeleteTask } from "@/hooks/use-tasks-queries"
import { useActiveSession, useStartSession, useStopSession } from "@/hooks/use-time-queries"
import { useTimerStore } from "@/stores/timer-store"
import { useTasksStore } from "@/stores/tasks-store"
import { cn } from "@/lib/utils"

interface TaskListItemProps {
  task: any
}

export function TaskListItem({ task }: TaskListItemProps) {
  const updateTask = useUpdateTask()
  const deleteTask = useDeleteTask()
  const setSelectedTaskId = useTasksStore((state) => state.setSelectedTaskId)

  const { data: activeSession } = useActiveSession()
  const startSession = useStartSession()
  const stopSession = useStopSession()

  const { countdownRemaining, elapsedSeconds } = useTimerStore()

  const isActive = activeSession?.taskId === task.id

  const handleTimerToggle = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (isActive) {
      // Pause/Stop: Stop the server session and save the exact time tracked so far
      stopSession.mutate()
    } else {
      // Start: Start a new server session
      startSession.mutate({
        taskId: task.id,
        projectId: task.projectId,
        type: task.estimatedTime ? "COUNTDOWN" : "NORMAL",
        description: `Working on: ${task.title}`
      })
    }
  }

  const completedChecklist = task.checklists?.filter((item: any) => item.isCompleted).length || 0
  const totalChecklist = task.checklists?.length || 0

  const priorityColors = {
    URGENT: "text-red-500 bg-red-500/10 border-red-500/20",
    HIGH: "text-orange-500 bg-orange-500/10 border-orange-500/20",
    MEDIUM: "text-blue-500 bg-blue-500/10 border-blue-500/20",
    LOW: "text-slate-500 bg-slate-500/10 border-slate-500/20",
    NO_PRIORITY: "text-muted-foreground bg-muted border-transparent",
  }

  const handleStatusToggle = (e: React.MouseEvent) => {
    e.stopPropagation()
    const newStatus = task.status === "DONE" ? "TODO" : "DONE"
    updateTask.mutate({ id: task.id, data: { status: newStatus } })
  }

  const formatTime = (minutes: number | null) => {
    if (!minutes) return null
    const h = Math.floor(minutes / 60)
    const m = minutes % 60
    return h > 0 ? `${h}h ${m}m` : `${m}m`
  }

  const isCountdown = !!task.estimatedTime

  return (
    <div
      onClick={() => setSelectedTaskId(task.id)}
      className={cn(
        "flex items-center gap-4 p-3 rounded-xl border bg-card hover:bg-accent/35 transition-all cursor-pointer group select-none duration-300",
        isActive && "border-primary/40 shadow-[0_0_12px_rgba(var(--primary-rgb),0.06)] bg-primary/2"
      )}
    >
      <button
        onClick={handleStatusToggle}
        className={cn(
          "w-4.5 h-4.5 rounded-full border border-primary flex items-center justify-center transition-all shrink-0 cursor-pointer",
          task.status === "DONE" ? "bg-primary text-primary-foreground" : "bg-transparent hover:bg-primary/10"
        )}
      >
        {task.status === "DONE" && (
          <span className="text-[10px] font-bold">Γ£ô</span>
        )}
      </button>

      <div className="flex-1 min-w-0 flex flex-col sm:flex-row sm:items-center justify-between gap-2">
        <div className="flex flex-col gap-1 min-w-0">
          <span
            className={cn(
              "text-sm font-semibold truncate text-foreground",
              task.status === "DONE" && "text-muted-foreground line-through"
            )}
          >
            {task.title}
          </span>
          {task.description && (
            <span className="text-xs text-muted-foreground truncate max-w-md">
              {task.description}
            </span>
          )}
        </div>

        <div className="flex items-center gap-3 flex-wrap sm:flex-nowrap">
          {task.project && (
            <Badge variant="outline" className="text-[10px] px-2 py-0 border-primary/10 text-primary bg-primary/5">
              <Bookmark className="w-2.5 h-2.5 mr-1" />
              {task.project.name}
            </Badge>
          )}

          <Badge variant="outline" className={cn("text-[10px] px-2 py-0", priorityColors[task.priority as keyof typeof priorityColors])}>
            <Flag className="w-2.5 h-2.5 mr-1 fill-current" />
            {task.priority.replace("_", " ")}
          </Badge>

          {task.dueDate && (
            <div className={cn(
              "flex items-center gap-1 text-xs text-muted-foreground px-1",
              new Date(task.dueDate) < new Date() && task.status !== "DONE" ? "text-red-500 font-medium" : ""
            )}>
              <Calendar className="w-3.5 h-3.5" />
              <span>{new Date(task.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}</span>
            </div>
          )}

          {totalChecklist > 0 && (
            <div className="flex items-center gap-1 text-xs text-muted-foreground px-1">
              <CheckSquare className="w-3.5 h-3.5" />
              <span>{completedChecklist}/{totalChecklist}</span>
            </div>
          )}

          <div className="flex items-center gap-2 pl-2 border-l border-border/40">
            {/* Time Display */}
            {(task.estimatedTime || task.actualTime || isActive) && (
              <div className={cn(
                "flex items-center gap-1 text-xs",
                isActive ? "text-primary font-bold" : "text-muted-foreground"
              )}>
                <Clock className={cn("w-3.5 h-3.5", isActive && "animate-spin-slow")} />
                {isActive ? (
                  <span className="font-mono font-bold">
                    {(() => {
                      const totalSeconds = isCountdown ? countdownRemaining : ((task.actualTime || 0) * 60 + elapsedSeconds)
                      const mins = Math.floor(totalSeconds / 60)
                      const secs = totalSeconds % 60
                      return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`
                    })()}
                    {isCountdown ? ` / ${formatTime(task.estimatedTime)}` : ""}
                  </span>
                ) : (
                  <span>
                    {task.actualTime ? `${formatTime(task.actualTime)} / ` : ""}
                    {formatTime(task.estimatedTime) || "No Est."}
                  </span>
                )}
              </div>
            )}

            <div className="flex items-center gap-1">
              {/* Play/Pause Button */}
              <button
                onClick={handleTimerToggle}
                className={cn(
                  "p-1 rounded-full border transition-all cursor-pointer flex items-center justify-center size-6 shrink-0",
                  isActive
                    ? "bg-primary/10 text-primary border-primary/25 hover:bg-primary/20"
                    : "bg-background border-border/80 text-muted-foreground hover:text-primary hover:border-primary/30"
                )}
                title={isActive ? "Pause timer" : "Start timer"}
              >
                {isActive ? (
                  <Pause className="size-2.5 fill-current stroke-none" />
                ) : (
                  <Play className="size-2.5 fill-current stroke-none ml-[1px]" />
                )}
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="shrink-0">
        <DropdownMenu>
          <DropdownMenuTrigger
            className={buttonVariants({ variant: "ghost", size: "icon", className: "h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity focus:opacity-100 cursor-pointer" })}
            onClick={(e) => e.stopPropagation()}
            aria-label="Task actions"
          >
            <MoreHorizontal className="h-4 w-4" />
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-40">
            <DropdownMenuItem onClick={() => setSelectedTaskId(task.id)}>View Details</DropdownMenuItem>
            <DropdownMenuItem onClick={() => updateTask.mutate({ id: task.id, data: { isFavorite: !task.isFavorite } })}>
              {task.isFavorite ? "Unfavorite" : "Favorite"}
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              className="text-destructive focus:bg-destructive focus:text-destructive-foreground"
              onClick={() => deleteTask.mutate(task.id)}
            >
              Delete
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useTasks, useUpdateTask } from "@/hooks/use-tasks-queries"
import { useTasksStore } from "@/stores/tasks-store"
import { TaskCard } from "./task-card"
import { Badge } from "@/components/ui/badge"
import { Plus } from "lucide-react"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"

const COLUMNS = [
  { id: "BACKLOG", label: "Backlog" },
  { id: "TODO", label: "Todo" },
  { id: "IN_PROGRESS", label: "In Progress" },
  { id: "DONE", label: "Done" },
  { id: "CANCELED", label: "Canceled" },
] as const

interface TasksKanbanProps {
  onNewTaskWithStatus: (status: string) => void
}

export function TasksKanban({ onNewTaskWithStatus }: TasksKanbanProps) {
  const { searchQuery, projectFilter, statusFilter } = useTasksStore()
  const { data: tasks, isLoading } = useTasks({
    projectId: projectFilter || undefined,
  })
  const updateTask = useUpdateTask()
  const [activeColumn, setActiveColumn] = useState<string | null>(null)

  const visibleColumns = statusFilter.length > 0
    ? COLUMNS.filter((col) => statusFilter.includes(col.id))
    : COLUMNS

  const gridColsClass = 
    visibleColumns.length === 1 ? "grid-cols-1 max-w-sm" :
    visibleColumns.length === 2 ? "grid-cols-1 md:grid-cols-2 max-w-2xl" :
    visibleColumns.length === 3 ? "grid-cols-1 md:grid-cols-3 max-w-4xl" :
    visibleColumns.length === 4 ? "grid-cols-1 md:grid-cols-4" :
    "grid-cols-1 md:grid-cols-5"

  if (isLoading) {
    return (
      <div className={cn("grid gap-4 py-6 overflow-x-auto", gridColsClass)}>
        {visibleColumns.map((col) => (
          <div key={col.id} className="flex flex-col gap-3 min-w-[240px] bg-muted/30 rounded-xl p-3 border h-[600px]">
            <div className="flex items-center justify-between">
              <span className="font-semibold text-sm">{col.label}</span>
              <span className="w-5 h-5 rounded-full bg-muted flex items-center justify-center text-xs">0</span>
            </div>
            <div className="space-y-3">
              <div className="h-28 border rounded-xl bg-card animate-pulse" />
              <div className="h-28 border rounded-xl bg-card animate-pulse" />
            </div>
          </div>
        ))}
      </div>
    )
  }

  // Client side filtering for search
  const filteredTasks = (tasks || []).filter((task: any) =>
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  )

  const handleDragStart = (e: React.DragEvent, taskId: string) => {
    e.dataTransfer.setData("text/plain", taskId)
  }

  const handleDragOver = (e: React.DragEvent, columnId: string) => {
    e.preventDefault()
    setActiveColumn(columnId)
  }

  const handleDrop = (e: React.DragEvent, columnId: string) => {
    e.preventDefault()
    setActiveColumn(null)
    const taskId = e.dataTransfer.getData("text/plain")
    if (taskId) {
      updateTask.mutate({ id: taskId, data: { status: columnId as any } })
    }
  }

  const getTasksByStatus = (status: string) => {
    return filteredTasks.filter((task: any) => task.status === status)
  }

  return (
    <div className={cn("grid gap-4 py-6 overflow-x-auto", gridColsClass)}>
      {visibleColumns.map((col) => {
        const columnTasks = getTasksByStatus(col.id)

        return (
          <div
            key={col.id}
            onDragOver={(e) => handleDragOver(e, col.id)}
            onDragLeave={() => setActiveColumn(null)}
            onDrop={(e) => handleDrop(e, col.id)}
            className={cn(
              "flex flex-col gap-3 min-w-[240px] bg-muted/30 rounded-xl p-3 border transition-colors duration-200 min-h-[600px] h-fit",
              activeColumn === col.id ? "bg-primary/5 border-primary/30" : "border-transparent"
            )}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span className="font-semibold text-sm text-foreground">{col.label}</span>
                <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded-full">
                  {columnTasks.length}
                </span>
              </div>

              <Button 
                variant="ghost" 
                size="icon" 
                className="h-7 w-7 rounded-lg text-muted-foreground hover:text-foreground"
                onClick={() => onNewTaskWithStatus(col.id)}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>

            <div className="flex flex-col gap-3 flex-1 overflow-y-auto">
              {columnTasks.map((task: any) => (
                <div
                  key={task.id}
                  draggable
                  onDragStart={(e) => handleDragStart(e, task.id)}
                  className="active:cursor-grabbing cursor-grab"
                >
                  <TaskCard task={task} />
                </div>
              ))}

              {columnTasks.length === 0 && (
                <div className="flex-1 border border-dashed border-border/60 rounded-xl flex items-center justify-center p-8 text-center text-xs text-muted-foreground">
                  No tasks here
                </div>
              )}
            </div>
          </div>
        )
      })}
    </div>
  )
}

"use client"

import { useTasks } from "@/hooks/use-tasks-queries"
import { useTasksStore } from "@/stores/tasks-store"
import { TaskListItem } from "./task-list-item"
import { Skeleton } from "@/components/ui/skeleton"
import { CheckSquare2 } from "lucide-react"

export function TasksList() {
  const { searchQuery, projectFilter, statusFilter, priorityFilter } = useTasksStore()

  // Pass filters down to the query
  const { data: tasks, isLoading, isError } = useTasks({
    projectId: projectFilter || undefined,
  })

  if (isLoading) {
    return (
      <div className="flex flex-col gap-2.5 py-6">
        {[...Array(6)].map((_, i) => (
          <div key={i} className="flex items-center gap-4 border rounded-xl p-4 bg-card h-[64px]">
            <Skeleton className="w-5 h-5 rounded-full" />
            <div className="space-y-2 flex-1">
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-3 w-32" />
            </div>
            <Skeleton className="w-24 h-6 rounded-md" />
            <Skeleton className="w-24 h-6 rounded-md" />
          </div>
        ))}
      </div>
    )
  }

  if (isError || !tasks) {
    return (
      <div className="py-20 flex flex-col items-center justify-center text-destructive">
        <p>Failed to load tasks</p>
      </div>
    )
  }

  // Client side filtering for search & status
  const filteredTasks = tasks.filter((task: any) => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))

    const matchesStatus = statusFilter.length === 0 || statusFilter.includes(task.status)
    const matchesPriority = priorityFilter.length === 0 || priorityFilter.includes(task.priority)

    return matchesSearch && matchesStatus && matchesPriority
  })

  if (filteredTasks.length === 0) {
    return (
      <div className="py-32 flex flex-col items-center justify-center text-muted-foreground">
        <CheckSquare2 className="w-12 h-12 mb-4 opacity-20" />
        <h3 className="text-lg font-medium text-foreground">No tasks found</h3>
        <p className="text-sm mt-1">Try adjusting your filters or create a new task.</p>
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-2.5 py-6">
      {filteredTasks.map((task: any) => (
        <TaskListItem key={task.id} task={task} />
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { useTimeTracker } from "@/hooks/use-time-tracker"
import { motion, AnimatePresence } from "framer-motion"
import { Square } from "lucide-react"
import { Button } from "@/components/ui/button"

function formatDuration(ms: number) {
  const totalSeconds = Math.floor(ms / 1000)
  const hours = Math.floor(totalSeconds / 3600)
  const minutes = Math.floor((totalSeconds % 3600) / 60)
  const seconds = totalSeconds % 60

  return `${hours.toString().padStart(2, "0")}:${minutes
    .toString()
    .padStart(2, "0")}:${seconds.toString().padStart(2, "0")}`
}

export function FloatingTimer() {
  const { isActive, startTime, description, stopTimer, setDescription } = useTimeTracker()
  const [elapsed, setElapsed] = React.useState(0)

  React.useEffect(() => {
    let interval: NodeJS.Timeout

    if (isActive && startTime) {
      setElapsed(Date.now() - startTime)
      interval = setInterval(() => {
        setElapsed(Date.now() - startTime)
      }, 1000)
    } else {
      setElapsed(0)
    }

    return () => clearInterval(interval)
  }, [isActive, startTime])

  return (
    <AnimatePresence>
      {isActive && (
        <motion.div
          initial={{ y: 100, opacity: 0, scale: 0.95 }}
          animate={{ y: 0, opacity: 1, scale: 1 }}
          exit={{ y: 100, opacity: 0, scale: 0.95 }}
          transition={{ type: "spring", stiffness: 400, damping: 30 }}
          className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-4 rounded-full border bg-card/90 p-2 pl-5 pr-2 shadow-2xl backdrop-blur-xl ring-1 ring-white/10"
        >
          <div className="flex items-center gap-3 border-r pr-4 border-border/50">
            <div className="relative flex h-3 w-3 items-center justify-center">
              <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-red-400 opacity-75"></span>
              <span className="relative inline-flex h-2 w-2 rounded-full bg-red-500"></span>
            </div>
            <span className="font-mono tabular-nums font-semibold text-sm tracking-widest text-foreground">
              {formatDuration(elapsed)}
            </span>
          </div>

          <input
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="What are you working on?"
            className="w-56 bg-transparent text-sm font-medium focus-visible:outline-none placeholder:text-muted-foreground/50 transition-colors"
          />

          <Button 
            variant="destructive" 
            size="icon" 
            className="size-9 rounded-full ml-2 shadow-sm shrink-0 transition-transform hover:scale-105 active:scale-95"
            onClick={stopTimer}
          >
            <Square className="size-3.5 fill-current" />
            <span className="sr-only">Stop timer</span>
          </Button>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

"use client"

import { useEffect, useRef } from "react"
import { motion, useDragControls } from "framer-motion"
import { useTimerStore } from "@/stores/timer-store"
import { useActiveSession, useStopSession } from "@/hooks/use-time-queries"
import { Button } from "@/components/ui/button"
import { Play, Pause, Square, GripHorizontal, Minimize2, Maximize2 } from "lucide-react"
import { cn } from "@/lib/utils"

export function FloatingTimer() {
  const { data: activeSession } = useActiveSession()
  const {
    isRunning,
    elapsedSeconds,
    timerType,
    pomodoroStage,
    countdownRemaining,
    resumeTimer,
    pauseTimer,
    tick,
    syncWithSession,
  } = useTimerStore()

  const stopSession = useStopSession()
  const dragControls = useDragControls()
  const constraintsRef = useRef<HTMLDivElement>(null)

  // Sync server session with client store
  useEffect(() => {
    if (activeSession) {
      syncWithSession(activeSession)
    } else {
      syncWithSession(null)
    }
  }, [activeSession, syncWithSession])

  // Run the clock tick interval
  useEffect(() => {
    let interval: NodeJS.Timeout
    if (isRunning) {
      interval = setInterval(() => {
        tick()
      }, 1000)
    }
    return () => clearInterval(interval)
  }, [isRunning, tick])

  if (!activeSession) return null

  const formatTime = (totalSeconds: number) => {
    const hrs = Math.floor(totalSeconds / 3600)
    const mins = Math.floor((totalSeconds % 3600) / 60)
    const secs = totalSeconds % 60
    return [
      hrs > 0 ? String(hrs).padStart(2, "0") : null,
      String(mins).padStart(2, "0"),
      String(secs).padStart(2, "0"),
    ].filter(Boolean).join(":")
  }

  const displayedTime = 
    timerType === "POMODORO" || timerType === "COUNTDOWN"
      ? formatTime(countdownRemaining)
      : formatTime(elapsedSeconds)

  const handlePlayPause = () => {
    if (isRunning) {
      pauseTimer()
    } else {
      resumeTimer()
    }
  }

  const handleStop = () => {
    stopSession.mutate()
  }

  return (
    <div ref={constraintsRef} className="fixed inset-0 pointer-events-none z-50">
      <motion.div
        drag
        dragListener={false}
        dragControls={dragControls}
        dragMomentum={false}
        dragConstraints={constraintsRef}
        initial={{ x: window.innerWidth - 320, y: window.innerHeight - 120 }}
        className="absolute pointer-events-auto flex items-center gap-4 p-3 bg-card/90 backdrop-blur-md border border-border/80 rounded-2xl shadow-xl w-72"
      >
        <div 
          onPointerDown={(e) => dragControls.start(e)}
          className="cursor-grab active:cursor-grabbing text-muted-foreground hover:text-foreground shrink-0"
        >
          <GripHorizontal className="h-4 w-4" />
        </div>

        <div className="flex flex-col flex-1 min-w-0">
          <div className="flex items-center gap-1.5">
            <span className="text-xs font-bold uppercase tracking-wider text-primary">
              {timerType === "POMODORO" ? `Pomo: ${pomodoroStage}` : timerType}
            </span>
          </div>
          <span className="font-mono text-xl font-bold tracking-tight mt-0.5">
            {displayedTime}
          </span>
          <span className="text-[10px] text-muted-foreground truncate max-w-[160px]">
            {activeSession.description || "No Description"}
          </span>
        </div>

        <div className="flex items-center gap-1.5 shrink-0">
          <Button 
            variant="outline" 
            size="icon" 
            className="h-8 w-8 rounded-lg"
            onClick={handlePlayPause}
          >
            {isRunning ? <Pause className="h-3.5 w-3.5" /> : <Play className="h-3.5 w-3.5 fill-current" />}
          </Button>
          <Button 
            variant="destructive" 
            size="icon" 
            className="h-8 w-8 rounded-lg"
            onClick={handleStop}
          >
            <Square className="h-3.5 w-3.5 fill-current" />
          </Button>
        </div>
      </motion.div>
    </div>
  )
}

