const RATING_CONFIG = [
  {
    key: "mood" as const,
    label: "Mood",
    emoji: "≡ƒÿè",
    levels: ["≡ƒÿ₧ Low", "≡ƒÿò Meh", "≡ƒÿÉ Okay", "≡ƒÿè Good", "≡ƒÿä Great"],
