    color: "bg-amber-400",
  },
  {
    key: "productivity" as const,
    label: "Focus",
    emoji: "≡ƒÄ»",
    levels: ["≡ƒÉó Slow", "≡ƒÿæ Mild", "≡ƒÆ╝ Decent", "≡ƒÜÇ Sharp", "≡ƒÅå Peak"],
