export function exportToJSON(data: any, filename: string) {
  const jsonString = JSON.stringify(data, null, 2)
  const blob = new Blob([jsonString], { type: "application/json" })
  downloadBlob(blob, `${filename}.json`)
}

export function exportToCSV(data: any[], filename: string) {
  if (data.length === 0) return

  const headers = Object.keys(data[0])
  const csvContent = [
    headers.join(","),
    ...data.map(row => 
      headers.map(header => {
        let val = row[header]
        if (val === null || val === undefined) val = ""
        // Escape quotes and wrap in quotes if contains comma
        const stringVal = String(val).replace(/"/g, '""')
        return stringVal.includes(",") ? `"${stringVal}"` : stringVal
      }).join(",")
    )
  ].join("\n")

  const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" })
  downloadBlob(blob, `${filename}.csv`)
}

function downloadBlob(blob: Blob, filename: string) {
  const link = document.createElement("a")
  const url = URL.createObjectURL(blob)
  link.setAttribute("href", url)
  link.setAttribute("download", filename)
  link.style.visibility = "hidden"
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
}

type LogMetadata = Record<string, any>

class Logger {
  private isProduction = process.env.NODE_ENV === "production"

  private formatMessage(level: string, message: string, meta?: LogMetadata) {
    const timestamp = new Date().toISOString()
    if (this.isProduction) {
      // Production: structured JSON logging for log aggregators
      return JSON.stringify({
        timestamp,
        level,
        message,
        ...meta,
      })
    } else {
      // Development: clean, human-readable console logging
      const metaString = meta && Object.keys(meta).length ? ` | ${JSON.stringify(meta)}` : ""
      const color = 
        level === "ERROR" ? "\x1b[31m" :
        level === "WARN" ? "\x1b[33m" :
        level === "INFO" ? "\x1b[32m" : "\x1b[37m"
      const reset = "\x1b[0m"
      return `[${timestamp}] ${color}${level}${reset}: ${message}${metaString}`
    }
  }

  info(message: string, meta?: LogMetadata) {
    console.log(this.formatMessage("INFO", message, meta))
  }

  warn(message: string, meta?: LogMetadata) {
    console.warn(this.formatMessage("WARN", message, meta))
  }

  error(message: string, meta?: LogMetadata) {
    console.error(this.formatMessage("ERROR", message, meta))
  }

  debug(message: string, meta?: LogMetadata) {
    if (!this.isProduction) {
      console.log(this.formatMessage("DEBUG", message, meta))
    }
  }
}

export const logger = new Logger()

import { logger } from "./logger"

interface RetryOptions {
  retries?: number
  delayMs?: number
  maxDelayMs?: number
  factor?: number
}

/**
 * Executes an asynchronous function with exponential backoff and jitter.
 */
export async function withRetry<T>(
  fn: () => Promise<T>,
  options: RetryOptions = {}
): Promise<T> {
  const retries = options.retries ?? 3
  const delayMs = options.delayMs ?? 500
  const maxDelayMs = options.maxDelayMs ?? 5000
  const factor = options.factor ?? 2

  let attempt = 0
  let currentDelay = delayMs

  while (true) {
    try {
      return await fn()
    } catch (error: any) {
      attempt++
      if (attempt > retries) {
        logger.error(`[RETRY_EXHAUSTED] Failed after ${attempt} attempts: ${error.message}`)
        throw error
      }

      // Add full jitter to prevent thundering herd problem
      const jitter = Math.random() * currentDelay
      const sleepTime = Math.min(maxDelayMs, currentDelay + jitter)

      logger.warn(`[RETRY_ATTEMPT] Attempt ${attempt} failed. Retrying in ${Math.round(sleepTime)}ms... Error: ${error.message}`)

      await new Promise((resolve) => setTimeout(resolve, sleepTime))

      currentDelay *= factor
    }
  }
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({
    request,
  })

  if (!process.env.NEXT_PUBLIC_SUPABASE_URL || !process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY) {
    return supabaseResponse
  }

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
          supabaseResponse = NextResponse.next({
            request,
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        },
      },
    }
  )

  // refreshing the auth token
  await supabase.auth.getUser()

  return supabaseResponse
}

import { createServerClient, type CookieOptions } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            )
          } catch {
            // The `setAll` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  )
}

