  pomodoroLongBreakDuration: number
  defaultCalendarView: "month" | "week" | "day" | "agenda"
  defaultTaskPriority: "NO_PRIORITY" | "LOW" | "MEDIUM" | "HIGH" | "URGENT"
  notificationsEnabled: boolean
  notificationSound: boolean
  reducedMotion: boolean
  highContrast: boolean
}

const DEFAULT_PREFERENCES: Preferences = {
  theme: "system",
  accentColor: "#3b82f6", // Default Blue
  fontSize: "base",
  uiDensity: "default",
  borderRadius: "xl",
  pomodoroWorkDuration: 25 * 60,
  pomodoroShortBreakDuration: 5 * 60,
  pomodoroLongBreakDuration: 15 * 60,
  defaultCalendarView: "week",
  defaultTaskPriority: "MEDIUM",
  notificationsEnabled: true,
  notificationSound: true,
  reducedMotion: false,
  highContrast: false,
}

interface PreferencesState {
  preferences: Preferences
  isLoading: boolean
  fetchPreferences: () => Promise<void>
  updatePreference: (key: keyof Preferences, value: any) => Promise<void>
  applyPreferences: (prefs: Preferences) => void
  resetPreferences: () => Promise<void>
}

export const usePreferencesStore = create<PreferencesState>()(
  persist(
    (set, get) => ({
      preferences: DEFAULT_PREFERENCES,
      isLoading: false,

      fetchPreferences: async () => {
        set({ isLoading: true })
        try {
          const res = await fetch("/api/settings")
          if (res.ok) {
            const data = await res.json()
            set({ preferences: data })
            get().applyPreferences(data)
          }
        } catch (err) {
          console.error("Failed to fetch preferences", err)
        } finally {
          set({ isLoading: false })
        }
      },

      updatePreference: async (key, value) => {
        const updatedPrefs = { ...get().preferences, [key]: value }
        set({ preferences: updatedPrefs })
        get().applyPreferences(updatedPrefs)

        try {
          await fetch("/api/settings", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ [key]: value }),
          })
        } catch (err) {
          console.error("Failed to sync preference with server", err)
        }
      },

      applyPreferences: (prefs) => {
        if (typeof window === "undefined") return

        const root = document.documentElement

        // 1. Apply Accent Color
        root.style.setProperty("--primary", prefs.accentColor)

        // 2. Apply Border Radius
        const radiusMap = {
          none: "0px",
          md: "0.5rem",
          lg: "0.75rem",
          xl: "1rem",
          full: "9999px",
        }
        root.style.setProperty("--radius", radiusMap[prefs.borderRadius] || "1rem")

        // 3. Apply Font Size
        const fontSizeMap = {
          sm: "14px",
          base: "16px",
          lg: "18px",
          xl: "20px",
        }
        root.style.fontSize = fontSizeMap[prefs.fontSize] || "16px"

        // 4. Apply UI Density
        if (prefs.uiDensity === "compact") {
          root.classList.add("density-compact")
        } else {
          root.classList.remove("density-compact")
        }

        // 5. Apply Accessibility: Reduced Motion
        if (prefs.reducedMotion) {
          root.classList.add("reduced-motion")
        } else {
          root.classList.remove("reduced-motion")
        }

        // 6. Apply Accessibility: High Contrast
        if (prefs.highContrast) {
          root.classList.add("high-contrast")
        } else {
          root.classList.remove("high-contrast")
        }
      },

      resetPreferences: async () => {
        set({ preferences: DEFAULT_PREFERENCES })
        get().applyPreferences(DEFAULT_PREFERENCES)

        try {
          await fetch("/api/settings", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(DEFAULT_PREFERENCES),
          })
        } catch (err) {
          console.error("Failed to reset preferences on server", err)
        }
      },
    }),
    {
      name: "chronos-preferences",
      onRehydrateStorage: () => (state) => {
        if (state) {
          state.applyPreferences(state.preferences)
        }
      },
    }
  )
)

import { create } from "zustand"
import { persist } from "zustand/middleware"

interface SearchItem {
  id: string
  type: "project" | "task" | "note" | "goal" | "habit" | "calendarEvent" | "command"
  title: string
  subtitle?: string
  color?: string
  metadata?: any
}

interface SearchState {
  isOpen: boolean
  query: string
  filterType: string | null
  selectedItem: SearchItem | null
  recentCommands: string[]

  setIsOpen: (isOpen: boolean) => void
  toggleOpen: () => void
  setQuery: (query: string) => void
  setFilterType: (filterType: string | null) => void
  setSelectedItem: (item: SearchItem | null) => void
  logCommand: (command: string) => void
  clearRecentCommands: () => void
}

export const useSearchStore = create<SearchState>()(
  persist(
    (set) => ({
      isOpen: false,
      query: "",
      filterType: null,
      selectedItem: null,
      recentCommands: [],

      setIsOpen: (isOpen) => set({ isOpen }),
      toggleOpen: () => set((state) => ({ isOpen: !state.isOpen })),
      setQuery: (query) => set({ query }),
      setFilterType: (filterType) => set({ filterType }),
      setSelectedItem: (selectedItem) => set({ selectedItem }),

      logCommand: (command) => set((state) => {
        const filtered = state.recentCommands.filter((c) => c !== command)
        return {
          recentCommands: [command, ...filtered].slice(0, 5),
        }
      }),

      clearRecentCommands: () => set({ recentCommands: [] }),
    }),
    {
      name: "chronos-search",
      partialize: (state) => ({
        recentCommands: state.recentCommands,
      }),
    }
  )
)

import { create } from "zustand"
import { persist } from "zustand/middleware"

const WORKSPACE_ID = "cm0q9z8x0000008l4f1h7a3n2"

export type TimerType = "NORMAL" | "POMODORO" | "STOPWATCH" | "COUNTDOWN" | "DEEP_WORK"
export type PomodoroStage = "WORK" | "SHORT_BREAK" | "LONG_BREAK"

interface TimerState {
  // Live Timer State
  activeSessionId: string | null
  isRunning: boolean
  startTime: number | null // timestamp in ms
  elapsedSeconds: number
  timerType: TimerType
  projectId: string | null
  taskId: string | null
  description: string
  tags: string

  // Pomodoro Specific State
  pomodoroStage: PomodoroStage
  pomodoroCycles: number
  pomodoroTargetCycles: number
  pomodoroWorkDuration: number // in seconds
  pomodoroShortBreakDuration: number // in seconds
  pomodoroLongBreakDuration: number // in seconds

  // Countdown Specific State
  countdownDuration: number // in seconds
  countdownRemaining: number // in seconds

  // Stopwatch Specific State
  stopwatchLaps: number[]
  stopwatchMilliseconds: number

  // Core Actions
  startTimer: (type: TimerType, projectId?: string | null, taskId?: string | null) => void
  pauseTimer: () => void
  resumeTimer: () => void
  stopTimer: () => void
  resetTimer: () => void
  tick: () => void
  syncWithSession: (session: any) => void

  // Setters
  setProject: (id: string | null) => void
  setTask: (id: string | null) => void
  setDescription: (desc: string) => void
  setTags: (tags: string) => void

  // Pomodoro Actions
  setPomodoroDurations: (work: number, short: number, long: number) => void
  setPomodoroTargetCycles: (target: number) => void
  nextPomodoroStage: () => void

  // Countdown Actions
  setCountdownDuration: (seconds: number) => void
}

export const useTimerStore = create<TimerState>()(
  persist(
    (set, get) => ({
      activeSessionId: null,
      isRunning: false,
      startTime: null,
      elapsedSeconds: 0,
      timerType: "NORMAL",
      projectId: null,
      taskId: null,
      description: "",
      tags: "",

      pomodoroStage: "WORK",
      pomodoroCycles: 0,
      pomodoroTargetCycles: 4,
      pomodoroWorkDuration: 25 * 60,
      pomodoroShortBreakDuration: 5 * 60,
      pomodoroLongBreakDuration: 15 * 60,

      countdownDuration: 10 * 60,
      countdownRemaining: 10 * 60,

      stopwatchLaps: [],
      stopwatchMilliseconds: 0,

      startTimer: (type, projectId = null, taskId = null) => {
        const now = Date.now()
        set({
          isRunning: true,
          startTime: now,
          elapsedSeconds: 0,
          timerType: type,
          projectId,
          taskId,
          description: "",
          tags: "",
          countdownRemaining: type === "COUNTDOWN" ? get().countdownDuration : 0,
          stopwatchLaps: [],
          stopwatchMilliseconds: 0,
        })
      },

      pauseTimer: () => {
        if (!get().isRunning) return
        // Save accumulated elapsed seconds
        const currentElapsed = get().elapsedSeconds
        set({
          isRunning: false,
          startTime: null,
          elapsedSeconds: currentElapsed,
        })
      },

      resumeTimer: () => {
        if (get().isRunning) return
        set({
          isRunning: true,
          startTime: Date.now() - (get().elapsedSeconds * 1000),
        })
      },

      stopTimer: () => {
        set({
          activeSessionId: null,
          isRunning: false,
          startTime: null,
          elapsedSeconds: 0,
        })
      },

      resetTimer: () => {
        set({
          isRunning: false,
          startTime: null,
          elapsedSeconds: 0,
          countdownRemaining: get().countdownDuration,
          stopwatchLaps: [],
          stopwatchMilliseconds: 0,
        })
      },

      tick: () => {
        const state = get()
        if (!state.isRunning || !state.startTime) return

        // DRIFT PREVENTION: Calculate elapsed time based on system clock, not setInterval counts
        const now = Date.now()
        const elapsed = Math.floor((now - state.startTime) / 1000)

        if (state.timerType === "COUNTDOWN") {
          const remaining = Math.max(0, state.countdownDuration - elapsed)
          set({ 
            elapsedSeconds: elapsed,
            countdownRemaining: remaining,
          })
          if (remaining === 0) {
            set({ isRunning: false })
            // Stop the session on the server to save the time entry
            fetch(`/api/time/session?workspaceId=${WORKSPACE_ID}`, { method: "DELETE" })
              .catch(err => console.error("Failed to auto-stop session:", err))

            // Trigger browser notification if allowed
            if ("Notification" in window && Notification.permission === "granted") {
              new Notification("Timer finished!", { body: "Your countdown timer has ended." })
            }
          }
        } else if (state.timerType === "POMODORO") {
          const stageDuration = 
            state.pomodoroStage === "WORK" ? state.pomodoroWorkDuration :
            state.pomodoroStage === "SHORT_BREAK" ? state.pomodoroShortBreakDuration :
            state.pomodoroLongBreakDuration

          const remaining = Math.max(0, stageDuration - elapsed)
          set({ 
            elapsedSeconds: elapsed,
            countdownRemaining: remaining, // Use countdownRemaining for Pomodoro progress
          })

          if (remaining === 0) {
            state.nextPomodoroStage()
          }
        } else {
          set({ elapsedSeconds: elapsed })
        }
      },

      syncWithSession: (session) => {
        if (!session) {
          set({
            activeSessionId: null,
            isRunning: false,
            startTime: null,
            elapsedSeconds: 0,
          })
          return
        }

        const startTimestamp = new Date(session.startTime).getTime()
        const now = Date.now()
        const elapsed = Math.floor((now - startTimestamp) / 1000)

        // Auto-detect task estimatedTime and set countdown based on remaining time
        const taskActualSeconds = session.task?.actualTime ? session.task.actualTime * 60 : 0
        const taskEstSeconds = session.task?.estimatedTime 
          ? Math.max(0, session.task.estimatedTime * 60 - taskActualSeconds) 
          : 0
        const isCountdown = session.type === "COUNTDOWN" || (session.type === "NORMAL" && taskEstSeconds > 0)
        const effectiveType = isCountdown ? "COUNTDOWN" : (session.type as TimerType)

        set({
          activeSessionId: session.id,
          isRunning: true,
          startTime: startTimestamp,
          elapsedSeconds: elapsed,
          timerType: effectiveType,
          projectId: session.projectId,
          taskId: session.taskId,
          description: session.description || "",
          tags: session.tags || "",
          countdownDuration: taskEstSeconds > 0 ? taskEstSeconds : get().countdownDuration,
          countdownRemaining: taskEstSeconds > 0 ? Math.max(0, taskEstSeconds - elapsed) : get().countdownRemaining,
        })
      },

      setProject: (id) => set({ projectId: id }),
      setTask: (id) => set({ taskId: id }),
      setDescription: (desc) => set({ description: desc }),
      setTags: (tags) => set({ tags }),

      setPomodoroDurations: (work, short, long) => set({
        pomodoroWorkDuration: work,
        pomodoroShortBreakDuration: short,
        pomodoroLongBreakDuration: long,
      }),

      setPomodoroTargetCycles: (target) => set({ pomodoroTargetCycles: target }),

      nextPomodoroStage: () => {
        const state = get()
        let nextStage: PomodoroStage = "WORK"
        let nextCycles = state.pomodoroCycles

        if (state.pomodoroStage === "WORK") {
          nextCycles += 1
          if (nextCycles % state.pomodoroTargetCycles === 0) {
            nextStage = "LONG_BREAK"
          } else {
            nextStage = "SHORT_BREAK"
          }
        }

        set({
          pomodoroStage: nextStage,
          pomodoroCycles: nextCycles,
          startTime: Date.now(),
          elapsedSeconds: 0,
        })

        if ("Notification" in window && Notification.permission === "granted") {
          const title = nextStage === "WORK" ? "Work Session Started" : "Time for a Break!"
          const body = nextStage === "WORK" ? "Focus on your tasks." : "Relax for a bit."
          new Notification(title, { body })
        }
      },

      setCountdownDuration: (seconds) => set({
        countdownDuration: seconds,
        countdownRemaining: seconds,
      }),
    }),
    {
      name: "fp-timer-store",
      partialize: (state) => ({
        pomodoroWorkDuration: state.pomodoroWorkDuration,
        pomodoroShortBreakDuration: state.pomodoroShortBreakDuration,
        pomodoroLongBreakDuration: state.pomodoroLongBreakDuration,
        pomodoroTargetCycles: state.pomodoroTargetCycles,
        countdownDuration: state.countdownDuration,
      }),
    }
  )
)

/**
 * GLOBAL DOMAIN ARCHITECTURE LAYER
 * As defined in the Official Domain Model & Data Architecture Bible
 * 
 * Strict Type definitions for all core and edge entities.
 */

// ============================================================================
// SHARED TYPES & ENUMS
// ============================================================================

export type UUID = string;
export type ISO8601 = string; // e.g., "2026-06-29T10:00:00Z"
export type HEXColor = string; // e.g., "#FF0000"

export enum EntityState {
  DRAFT = "DRAFT",
  ACTIVE = "ACTIVE",
  IN_PROGRESS = "IN_PROGRESS",
  PAUSED = "PAUSED",
  RUNNING = "RUNNING",
  COMPLETED = "COMPLETED",
  CANCELLED = "CANCELLED",
  ARCHIVED = "ARCHIVED",
  DELETED = "DELETED"
}

export enum PriorityLevel {
  URGENT = 4,
  HIGH = 3,
  MEDIUM = 2,
  LOW = 1,
  NONE = 0
}

export interface BaseEntity {
  id: UUID;
  createdAt: ISO8601;
  updatedAt: ISO8601;
  deletedAt?: ISO8601 | null;
  state: EntityState;
}

// ============================================================================
// CORE ENTITIES (Hierarchy)
// ============================================================================

export interface Workspace extends BaseEntity {
  name: string;
  ownerId: UUID;
  settings: Record<string, any>;
}

export interface Project extends BaseEntity {
  workspaceId: UUID;
  name: string;
  description?: string;
  color: HEXColor;
  icon?: string;
  startDate?: ISO8601;
  dueDate?: ISO8601;
  isFavorite: boolean;
}

export interface Task extends BaseEntity {
  projectId: UUID | null; // Nullable for Inbox tasks
  parentId: UUID | null; // For Subtasks
  title: string;
  description?: string;
  priority: PriorityLevel;
  dueDate?: ISO8601;
  completedAt?: ISO8601 | null;
  order: number;
  tags: UUID[];
}

// ============================================================================
// TIME & PRODUCTIVITY ENTITIES
// ============================================================================

export enum SessionType {
  POMODORO = "POMODORO",
  DEEP_WORK = "DEEP_WORK",
  BREAK = "BREAK",
  MEETING = "MEETING"
}

export interface TimeEntry extends BaseEntity {
  taskId: UUID | null;
  projectId: UUID | null;
  startTime: ISO8601;
  endTime?: ISO8601 | null;
  durationSeconds: number;
  description?: string;
  sessionType: SessionType;
}

export interface CalendarEvent extends BaseEntity {
  title: string;
  description?: string;
  startTime: number; // Minutes from midnight (e.g., 540 = 9:00 AM)
  duration: number; // Minutes
  color: string; // Tailwind class or HEX
  projectId: UUID | null;
}

export interface DailyPlanner extends BaseEntity {
  date: ISO8601; // YYYY-MM-DD
  focusObjective: string;
  energyLevel: number; // 1-10
  rating?: number;
}

// ============================================================================
// GOALS & HABITS ENTITIES
// ============================================================================

export interface Goal extends BaseEntity {
  title: string;
  description?: string;
  targetDate: ISO8601;
  progress: number; // 0.0 to 1.0
  color: HEXColor;
  icon: string;
  milestones: Milestone[];
}

export interface Milestone extends BaseEntity {
  goalId: UUID;
  title: string;
  isCompleted: boolean;
  dueDate?: ISO8601;
}

export interface Habit extends BaseEntity {
  title: string;
  description?: string;
  frequency: "DAILY" | "WEEKLY" | "MONTHLY";
  color: HEXColor;
  icon: string;
  history: Record<string, boolean>; // Key: YYYY-MM-DD, Value: completed
  streak: number;
  longestStreak: number;
}

// ============================================================================
// KNOWLEDGE & CONTENT ENTITIES
// ============================================================================

export interface Note extends BaseEntity {
  folderId: UUID | null;
  title: string;
  content: string; // Markdown string
  tags: UUID[];
  isPinned: boolean;
}

export interface Folder extends BaseEntity {
  parentId: UUID | null;
  name: string;
  color: HEXColor;
  icon: string;
}

export interface Tag extends BaseEntity {
  name: string;
  color: HEXColor;
}

// ============================================================================
// SYSTEM & SETTINGS ENTITIES
// ============================================================================

export interface AppSettings {
  theme: "light" | "dark" | "system";
  accentColor: HEXColor;
  timeZone: string;
  startOfWeek: 0 | 1 | 6; // Sunday, Monday, Saturday
  enableNotifications: boolean;
  soundEnabled: boolean;
}

export interface Notification extends BaseEntity {
  userId: UUID;
  title: string;
  message: string;
  actionUrl?: string;
  isRead: boolean;
  type: "INFO" | "SUCCESS" | "WARNING" | "ERROR";
}

// ============================================================================
// STORE STATE INTERFACES
// ============================================================================

export interface OrganizationState {
  projects: Project[];
  tasks: Task[];
  addProject: (name: string, color: string) => void;
  addTask: (title: string, projectId: string | null) => void;
  updateTaskStatus: (taskId: string, status: EntityState) => void;
  deleteTask: (taskId: string) => void;
  reorderTasks: (startIndex: number, endIndex: number) => void;
}
